// Banque Douleur — format sandbox.js
// o: tableau des options, a: index de la bonne réponse, e: explication
window.DOULEUR_BANK=[
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"L'activation du récepteur NMDA provoque une entrée de :",o:["Ca²⁺, na⁺ et sortie de k⁺","Uniquement cl⁻","Uniquement na⁺"],a:0,e:"NMDA-R activé → afflux Ca²⁺ + Na⁺ + efflux K⁺. L'entrée de Ca²⁺ est cruciale pour la LTP et la sensibilisation centrale."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La prévalence mondiale de la douleur chronique en fait :",o:["La principale cause d'invalidité dans le monde","La principale cause de consultation en psychiatrie","La 3ème cause de mortalité mondiale"],a:0,e:"Douleur chronique = 1ère cause d'invalidité mondiale (Roberts NL et al. 2018, Lancet). > 30% population mondiale (Cohen 2021, Lancet). Principale raison de consultation médicale."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel ion est particulièrement crucial dans le déclenchement de la LTP spinale ?",o:["Na⁺ (sodium via Nav)","Ca²⁺ (calcium intracellulaire via NMDA-R)","Cl⁻ (chlorure via GABA-A)"],a:1,e:"NMDA-R activé → entrée Ca²⁺ → activation PKC + CaMKII → phosphorylation AMPA-R → ↑ conductance → LTP. L'entrée de Ca²⁺ est le déclencheur clé."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel médicament est particulièrement utile pour la douleur neuropathique avec insomnie associée ?",o:["Ibuprofène (anti-inflammatoire sans effet sur le sommeil)","Duloxétine (prise matinale recommandée)","Amitriptyline (effet sédatif nocturne utile)"],a:2,e:"Amitriptyline = tricyclique → sédatif → utile si insomnie associée à la douleur neuropathique. Prise au coucher (10 mg → 25-50 mg). Duloxétine = prise matinale (risque nausées)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Dans quelle condition un programme d'exercice physique est-il déconseillé en premier lieu selon les guidelines actuelles ?",o:["La douleur neuropathique sévère","La fibromyalgie","La douleur chronique primaire non oncologique est la principale indication de l'exercice"],a:2,e:"Pour douleur chronique primaire non oncologique : les guidelines (OMS 2018, NICE) recommandent en PREMIER l'exercice + éducation + psychothérapie, AVANT les analgésiques conventionnels."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La diminution de matière grise dans le CPFdl bilatéral est associée à :",o:["La douleur lombaire chronique neuropathique ET non neuropathique","Uniquement la douleur cancéreuse","Uniquement la fibromyalgie"],a:0,e:"Apkarian et al. 2004 : ↓ matière grise CPFdl bilatéral dans douleur lombaire chronique (neuropathique ET non neuropathique). → explique ↓ fonctions cognitives exécutives."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Le métabolisme de la lidocaïne se fait principalement au niveau :",o:["Du foie (métabolisme hépatique)","Du rein","Des poumons"],a:0,e:"Lidocaïne (anesthésique amide) = métabolisme hépatique. Contre-indiquée en insuffisance hépatique sévère. Max 4,5 mg/kg sans adrénaline. Toxicité SNC et cardiovasculaire en cas de surdosage."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel canal est activé par la chaleur > 42°C et la capsaïcine ?",o:["Trpv1","Asic","Piezo2"],a:0,e:"TRPV1 = chaleur > 42°C + protons + capsaïcine. TRPA1 = froid intense. ASIC = protons. Piezo2 = mécanique."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La théorie de convergence-facilitation explique :",o:["La douleur référée","Le wind-up","La modulation descendante par la pag"],a:0,e:"Afférences viscérales + somatiques convergent sur mêmes neurones → douleur référée (ex : infarctus → bras)."},
{ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Les ACEs augmentent le risque de douleur chronique généralisée de :",o:["1,5 fois","5 à 6 fois","2 à 3 fois"],a:2,e:"Afari 2014 : ACEs → ↑ 2 à 3 fois. Pathologies : fibromyalgie, SFC, côlon irritable, ATM, douleur pelvienne."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La voie spinothalamique latérale transmet :",o:["Les informations proprioceptives","La localisation et l'intensité de la douleur","L'aspect émotionnel de la douleur"],a:1,e:"Spinothalamique latérale → noyau VPL thalamus → aspects sensoriels-discriminatifs."},
{ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'alliance thérapeutique agit sur la douleur via :",o:["La prescription médicamenteuse","Génération d'attentes positives activant l'analgésie endogène","La technique manuelle appliquée"],a:1,e:"Alliance → attentes positives → opioïdes endogènes, dopamine, endocannabinoïdes (Bialosky 2017)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel signal d'alerte impose l'arrêt immédiat d'une séance de kiné sous statines ?",o:["Fatigue musculaire normale post-exercice","Légère myalgie apparaissant après 30 minutes d'effort","Douleur soudaine et intense dans un tendon ou muscle (CK à surveiller)"],a:2,e:"Statines → myalgie/myopathie. Signal d'alerte : douleur musculaire soudaine intense → arrêter + décharger + échographie + orienter médecin (CK si > 5x normale → arrêter la statine)."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"L'hippocampe est impliqué dans la douleur chronique par :",o:["↓ glutamate, ↓ ltp, activation microglie","↑ libération substance p","↑ activité spinothalamique"],a:0,e:"Hippocampe dans douleur chronique : ↓ glutamate + ↓ LTP + activation microglie. Impliqué dans formation et maintien de la douleur neuropathique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel médicament nécessite une prophylaxie systématique par laxatif lors de sa prescription ?",o:["Les opioïdes (morphine, oxycodone, fentanyl)","Les AINS (ibuprofène, diclofénac)","Les gabapentinoïdes (prégabaline)"],a:0,e:"Opioïdes → constipation quasi-systématique (MOR entériques) → toujours prescrire laxatifs prophylactiques. AINS → risque GI différent (ulcère). Gabapentine → œdème, pas constipation."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel est l'objectif principal d'un bloc anesthésique avant rééducation ?",o:["Guérir définitivement la pathologie sous-jacente","Remplacer le traitement de kinésithérapie","Créer une fenêtre d'analgésie pour améliorer la fonction et l'adhésion à l'exercice"],a:2,e:"Bloc anesthésique = fenêtre d'analgésie pour rééducation précoce. Effet modeste et court terme (quelques semaines). Rôle = faciliter l'exercice, pas se substituer à lui."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les fibres Aβ en conditions normales :",o:["Transmettent le toucher non nociceptif — ne provoquent pas de douleur","Transmettent la douleur rapide précise","Sont non myélinisées et lentes"],a:0,e:"Fibres Aβ = myélinisées, grand diamètre, très rapides (~70 m/s). En conditions normales = toucher non nociceptif + proprioception. Peuvent devenir 'nociceptives' après réorganisation anatomique."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le récepteur NK1 est activé par :",o:["La substance P","Le glutamate","Le CGRP"],a:0,e:"NK1 (récepteur neurokinine 1) = activé par substance P. Présent dans 80% des neurones de projection de la corne dorsale → wind-up + sensibilisation centrale."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La potentialisation à long terme (LTP) spinale est associée à :",o:["Une diminution de l'excitabilité neuronale","Une augmentation persistante de l'excitabilité neuronale → sensibilisation centrale","Une réduction du phénomène de wind-up"],a:1,e:"LTP spinale = plasticité synaptique à long terme → ↑ excitabilité persistante → sensibilisation centrale. Générée par stimulation HF des fibres C."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La douleur neuropathique est définie comme :",o:["Douleur causée par une lésion ou une maladie du système somatosensoriel","Douleur résultant d'une activation des nocicepteurs sans lésion nerveuse","Douleur diffuse sans explication biomédicale"],a:0,e:"Douleur neuropathique (IASP) = causée par lésion/maladie du système somatosensoriel. Nociceptive = activation nocicepteurs. Nociplastique = altération nociception sans lésion évidente."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"L'ATP libéré par les tissus endommagés stimule :",o:["Les récepteurs p2x3 des fibres c","Les récepteurs nk1 des neurones de projection","Les récepteurs nmda de la corne dorsale"],a:0,e:"ATP → récepteurs purinergiques P2X3 des fibres C → nociception. Rôle dans la sensibilisation périphérique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Les anesthésiques locaux de type amide incluent :",o:["Lidocaïne et bupivacaïne","Procaïne et tétracaïne","Cocaïne et benzocaïne"],a:0,e:"Amides : lidocaïne, bupivacaïne, ropivacaïne, mépivacaïne. Esters : procaïne, tétracaïne, cocaïne. Contre-indication amides : allergie + insuffisance hépatique sévère (métabolisme hépatique)."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'auto-efficacité est différente de la capacité réelle car :",o:["Elle ne peut pas être modifiée par l'intervention thérapeutique","Elle repose sur la croyance subjective, pas sur les capacités objectives mesurées","Elle est toujours supérieure à la capacité réelle"],a:1,e:"Auto-efficacité = croyance subjective. Un patient peut avoir de grandes capacités physiques mais faible auto-efficacité (et vice versa). Elle est modifiable par l'exposition progressive + feedback."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"En Espagne, quel pourcentage de patients souffrant de douleur chronique estime recevoir un traitement inadéquat ?",o:["10%","29%","60%"],a:1,e:"Baromètre 2022 : 29% estiment recevoir traitement inadéquat. 58% estiment la formation sur leur maladie insuffisante. 70% souhaitent plus d'informations sur le traitement."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel neuropeptide libéré par les fibres C provoque vasodilatation et extravasation ?",o:["Glutamate et aspartate","Substance p et cgrp","Gaba et glycine"],a:1,e:"SP + CGRP → inflammation neurogène. Le CGRP joue aussi un rôle clé dans la migraine."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel récepteur, en plus du glutamate, doit être activé pour que le NMDA-R s'ouvre ?",o:["La noradrénaline via α2","La substance P via NK1","La glycine doit également se lier au NMDA-R"],a:2,e:"NMDA-R = double serrure : glutamate (site principal) + glycine (site co-agoniste) + dépolarisation membranaire pour lever le blocage par Mg²⁺."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La tDCS en mode anode produit :",o:["Des potentiels d'action dans le cortex","Une diminution de l'excitabilité","Une augmentation de l'excitabilité neuronale"],a:2,e:"Anode tDCS → ↑ excitabilité. Cathode → ↓ excitabilité. Ne génère PAS de PA (≠ rTMS)."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La douleur mixte correspond à :",o:["Douleur avec une composante nociceptive prédominante","Superposition complexe des types nociceptif, neuropathique et nociplastique","Douleur uniquement d'origine centrale"],a:1,e:"Douleur mixte = superposition complexe des 3 types. Fréquente en pratique clinique (ex : lombosciatalgie chronique avec composante nociplastique)."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les récepteurs cannabinoïdes CB1 et CB2 activés produisent :",o:["↓ AMPc intracellulaire → ↓ effets excitateurs sur les neurones","Activation de PLC → ↑ Ca²⁺ intracellulaire","↑ AMPc → excitation neuronale"],a:0,e:"CB1 + CB2 → couplés à Gi → ↓ AMPc → ↓ excitabilité neuronale + prévention dégranulation mastocytes + ↓ médiateurs pro-inflammatoires."},
{ch:"Classification",label:"Classification",type:"direct",q:"Dans l'algorithme Pain in Motion, quelle est la première question ?",o:["La douleur est-elle présente depuis plus de 3 mois ?","Existe-t-il une douleur neuropathique pouvant expliquer le tableau ?","Le csi est-il ≥ 40 ?"],a:1,e:"Algorithme Nijs 2016 : 1) Neuropathique ? 2) Disproportionnée ? 3) Diffuse ? 4) CSI ≥ 40 ? Toujours commencer par éliminer la neuropathique."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Le 'contact avec le présent' dans l'ACT correspond à :",o:["Se souvenir d'expériences passées sans douleur","La pleine conscience — être attentif à l'expérience du moment présent","Planifier des activités futures agréables"],a:1,e:"Contact avec le présent (ACT) = pleine conscience, attention au moment présent. Un des 6 processus clés de l'ACT avec acceptation, défusion, moi observateur, valeurs, action engagée."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les fibres C représentent environ quel pourcentage des afférences nociceptives ?",o:["30%","50%","70%"],a:2,e:"Fibres C = 70% des afférences nociceptives. Non myélinisées, lentes (~2 m/s), polymodales."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La douleur sociale (rejet, isolement) active les mêmes zones que la douleur physique. Cette découverte implique que :",o:["La douleur physique et sociale sont identiques et traitées pareil","Le paracétamol devrait être prescrit pour tous les problèmes relationnels","Les interventions psychosociales et la connexion sociale ont un impact neurobiologique réel sur la douleur"],a:2,e:"Même circuit (CCAd + insula) → les interventions psychosociales + soutien social ont un impact neurobiologique réel sur la douleur. Isolement = aggrave la douleur chronique biologiquement."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le cortex préfrontal dorsolatéral (CPFdl) joue un rôle dans :",o:["La transduction des stimuli thermiques","La modulation descendante de la douleur","La transmission spinothalamique directe"],a:1,e:"CPFdl → modulation descendante + fonctions cognitives de la douleur. Sa matière grise ↓ dans douleur chronique."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La posologie maximale du paracétamol chez l'adulte sain est :",o:["4 g/jour","3 g/jour","6 g/jour"],a:0,e:"Paracétamol max = 4 g/jour. Réduire à ≤ 3 g/jour chez > 65 ans ou hépatopathie légère."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Un patient sous anticoagulants doit faire de la kiné avec thérapie manuelle profonde. Quelle précaution ?",o:["Éviter les techniques manuelles trop profondes — risque d'hématome","Doubler la dose d'anticoagulant avant la séance","Appliquer de la chaleur intense pour fluidifier le sang"],a:0,e:"Anticoagulants + thérapie manuelle profonde = risque hématome. Préférer pressions modérées. Pour ponction sèche : contre-indiquée ou protocole strict + vérifier délai depuis dernière dose."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Le tramadol est contre-indiqué en cas de :",o:["Iléus paralytique","Épilepsie non contrôlée","Insuffisance hépatique sévère"],a:1,e:"Tramadol contre-indiqué : épilepsie non contrôlée + IRC sévère. Tapentadol → ins. hépatique. Morphine → iléus."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Selon Leventhal, la représentation 'identité' de la maladie correspond à :",o:["L'attribution de la douleur à une cause spécifique ('ma douleur = ma hernie')","La conviction que l'exercice aggrave la douleur","La croyance que la douleur durera toujours"],a:0,e:"Leventhal 5 représentations : identité (attribution à une cause) + cause + conséquence + chronologie + contrôle/guérison. L'identité = 'ma douleur EST ma hernie/arthrose' → comportements passifs."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Selon Rossettini et al. (2018), le contexte thérapeutique peut déclencher des effets placebo par :",o:["Uniquement la technique appliquée","Les rituels cliniques, les symboles et les interactions thérapeute-patient","Uniquement la communication verbale"],a:1,e:"Rossettini 2018 : contexte thérapeutique = rituels + symboles + interactions → effets placebo actifs. Ce n'est pas que la technique qui compte."},
{ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La défusion cognitive dans l'ACT consiste à :",o:["Remplacer les pensées négatives par des positives","Voir ses pensées comme des événements mentaux, pas des faits","Éliminer les pensées négatives"],a:1,e:"Défusion = changer la RELATION avec la pensée, pas la pensée elle-même."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'interaction opioïde + benzodiazépine expose à :",o:["Insuffisance rénale aiguë","Syndrome sérotoninergique","Dépression respiratoire"],a:2,e:"Opioïde + BZD → dépression respiratoire → prescrire naloxone. Syndrome sérotoninergique = tramadol + ISRS."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quelle fibre transmet la douleur rapide et précise ?",o:["Fibre c (non myélinisée)","Fibre aβ (non nociceptive)","Fibre aδ (myélinisée)"],a:2,e:"Aδ = myélinisée, rapide → douleur vive et précise immédiate. Fibre C = douleur diffuse secondaire."},
{ch:"Classification",label:"Classification",type:"direct",q:"Le modèle biopsychosocial a été introduit par :",o:["Vlaeyen en 1992","Engel dans les années 1960-70","Gifford dans les années 1990"],a:1,e:"Engel = biopsychosocial (1960-70). Gifford = organisme mature (1990). Vlaeyen = peur-évitement (1992). Stilwell = enactif (2019)."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La matrice de décision rapide recommande l'ACT en premier pour :",o:["L'évitement rigide et la paralysie par analyse","Le stress élevé et l'insomnie","Le catastrophisme élevé et la peur du mouvement"],a:0,e:"ACT = premier choix pour évitement rigide + paralysie par analyse. Complément : exposition graduée en kiné. TCC = catastrophisme + kinésiophobie. Mindfulness = stress + insomnie."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel est le rôle principal des récepteurs AMPA dans la transmission nociceptive ?",o:["Excitation rapide post-synaptique via entrée de Na⁺","Inhibition via entrée de Cl⁻","Modulation lente via AMPc"],a:0,e:"AMPA-R = récepteurs ionotropiques du glutamate → excitation rapide via Na⁺. Les NMDA-R assurent l'excitation plus lente/prolongée avec entrée de Ca²⁺."},
  {ch:"Classification",label:"Classification",type:"direct",q:"L'indice de douleur diffuse (WPI - Widespread Pain Index) a un seuil de référence de :",o:["≥ 7","≥ 15","≥ 3"],a:0,e:"WPI (Widespread Pain Index) seuil ≥ 7 = douleur diffuse. Utilisé dans l'algorithme de Pain in Motion pour la question 'douleur diffuse ?'. Fait partie des critères diagnostiques de la fibromyalgie."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Selon la définition internationale, le droit à la reconnaissance de la douleur correspond à :",o:["L'Article 1er de la Déclaration universelle des droits de l'homme","La Convention de Genève sur les soins médicaux","L'Article 2 du droit des personnes souffrant de douleur à être informées sur son évaluation et sa gestion"],a:2,e:"Article 2 : 'Le droit des personnes souffrant de douleur à la reconnaissance de leur douleur et à être informées sur la manière dont celle-ci peut être évaluée et prise en charge.'"},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La diathermie profonde est contre-indiquée en cas d'hypotension marquée sous :",o:["Benzodiazépines","Paracétamol","Gabapentine"],a:0,e:"Benzodiazépines + diathermie profonde = contre-indication relative si hypotension marquée. BZD → dépression respiratoire + hypotension → risque aggravé par diathermie."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La LTP dans la corne dorsale est déclenchée par :",o:["Stimulation haute fréquence des fibres c → nmda-r → ↑ ca²⁺","Activation des récepteurs gaba-a","Stimulation basse fréquence des fibres aβ"],a:0,e:"LTP = stimulation HF fibres C → NMDA-R → ↑ Ca²⁺ → plasticité synaptique durable."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Où se situent les corps cellulaires des neurones somatosensoriels pour le reste du corps (hors tête) ?",o:["Ganglion de la racine dorsale (GRD)","Ganglion trigéminal","Ganglion nodulaire du nerf vague"],a:0,e:"GRD = corps cellulaires afférents primaires pour le reste du corps. GT = tête/visage. Ganglion nodulaire = nerf vague (viscères)."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"L'hyperalgésie secondaire est le signe de :",o:["Sensibilisation périphérique","Sensibilisation centrale","Lésion tissulaire localisée"],a:1,e:"Hyperalgésie secondaire = hors du site lésé → sensibilisation centrale. Primaire (sur site) = périphérique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La naproxène est dosé à :",o:["400-600 mg/8h (max 2400 mg/jour)","250-500 mg/12h (max 1000 mg/jour)","50 mg/8-12h (max 150 mg/jour)"],a:1,e:"Naproxène : 250-500 mg/12h, max 1000 mg/j. Ibuprofène : 400-600 mg/8h, max 2400 mg/j. Diclofénac : 50 mg/8-12h, max 150 mg/j."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La réorganisation anatomique après lésion nerveuse peut provoquer de l'allodynie car :",o:["Les fibres c migrent vers les couches v et vi","Les fibres aδ disparaissent et sont remplacées par des fibres c","Les fibres aβ se ramifient vers la lame ii"],a:2,e:"Fibres Aβ (toucher) → ramification vers lame II → le toucher devient douloureux = allodynie mécanique."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quelle stratégie est recommandée en kiné pour utiliser l'ACT lors d'une exposition à un mouvement redouté ?",o:["1 respiration → identifier la pensée → effectuer la version sécurisée du mouvement","Attendre que la pensée disparaisse avant de bouger","Supprimer la pensée et forcer le mouvement"],a:0,e:"Protocole ACT + kiné : avant mouvement redouté → 1 respiration + identifier la pensée (défusion) + effectuer version sécurisée. Ne pas supprimer la pensée NI attendre sa disparition."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Selon Marvel et al. (1999), que se passerait-il si le soignant laissait le patient parler 2 minutes sans l'interrompre ?",o:["Le patient oublierait sa plainte principale","Le patient aurait exprimé tout ce qu'il avait à dire","Le patient continuerait de parler pendant 30 minutes"],a:1,e:"Langewitz et al. (2002) : réponse à une question ouverte = 2 minutes maximum sans interruption. Marvel (1999) : on interrompt en moyenne après 23 secondes. Laisser parler = base de l'entretien clinique."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La conduction sautillante (saltatoire) est propre aux :",o:["Fibres non myélinisées (groupe C)","Fibres myélinisées (groupe A)","Les deux types de fibres"],a:1,e:"Conduction saltatoire = PA 'saute' de nœud de Ranvier en nœud de Ranvier → beaucoup plus rapide. Propre aux fibres myélinisées Aδ et Aβ."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La stimulation rTMS à 10 Hz sur le cortex préfrontal dorsolatéral est utilisée quand :",o:["Le patient présente une épilepsie bien contrôlée","La douleur est uniquement nociceptive","Il y a une dépression associée à la douleur chronique"],a:2,e:"rTMS 10 Hz sur CPFdl = protocole pour dépression associée à douleur chronique. rTMS HF (≥5-10 Hz) sur M1 controlatéral = douleur neuropathique. Épilepsie non contrôlée = contre-indication absolue."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quelle est la définition de l'affrontement actif de la douleur ?",o:["Utilisation de stratégies comportementales et cognitives pour gérer la douleur","Ignorer complètement la douleur pour maintenir les activités","Dépendre exclusivement des médicaments pour gérer la douleur"],a:0,e:"Affrontement actif = stratégies comportementales (exercice, soins personnels) + cognitives (restructuration, acceptation). ≠ gestion passive (médicaments seuls, repos, résignation)."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"L'hypervigilance à la douleur est considérée comme :",o:["Inadaptée — elle amplifie la douleur et l'auto-entretient","Adaptée et bénéfique pour la guérison","Un mécanisme de protection normale"],a:0,e:"Hypervigilance = inadaptée. Attention soutenue + inflexible sur la douleur → amplification + auto-renforcement. Associée à anxiété + peur + catastrophisme → cercle vicieux."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les fibres Aδ font synapse dans la corne dorsale aux couches :",o:["I et v","I et ii","Ii et iv"],a:0,e:"Fibres Aδ → couches I et V. Fibres C → couches I et II."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"L'hypervigilance à la douleur peut être intentionnelle (top-down) ou :",o:["Volontaire uniquement","Uniquement déclenchée par des stimuli physiques","Automatique (bottom-up)"],a:2,e:"Vigilance à la douleur : top-down (intentionnelle, dépendante d'objectifs) ET bottom-up (automatique, captée par la menace potentielle). L'hypervigilance = schéma altéré où l'attention devient inflexible."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La noradrénaline (NE) via les récepteurs α2 présynaptiques produit :",o:["Excitation via ↑ AMPc","Activation des voies PLC/PKC","Inhibition de l'entrée de Ca²⁺ → ↓ libération de NE"],a:2,e:"α2 présynaptiques = autorécepteurs → Gi → ↓ Ca²⁺ → ↓ libération NE. α1 et β postsynaptiques → excitateurs. La NE peut donc avoir des effets opposés selon le récepteur."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'oxycodone est préféré à la morphine dans certains cas car :",o:["Meilleure biodisponibilité orale","N'est pas contre-indiqué en cas d'iléus paralytique","Moins de risque de constipation"],a:0,e:"Oxycodone = meilleure biodisponibilité orale que morphine. Mêmes indications et contre-indications que morphine. Risque dépression respiratoire et euphorie identiques."},
{ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La douleur sociale active :",o:["Uniquement le cortex somatosensoriel primaire","Uniquement les nocicepteurs périphériques","Le ccad et l'insula antérieure — mêmes zones que la douleur physique"],a:2,e:"Douleur sociale → CCAd + insula = mêmes zones que douleur physique. Paracétamol réduit aussi la douleur sociale !"},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel canal s'ouvre lors de la repolarisation du potentiel d'action ?",o:["Canal nav (sodium voltage-dépendant)","Canal kv","Canal vocc"],a:1,e:"Séquence PA : Nav s'ouvre (dépolarisation) → Nav se ferme + Kv s'ouvre (repolarisation) → sortie K⁺."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Les critères FACULTATIFS de la douleur nociplastique (IASP 2021) incluent :",o:["Tests neurodynamiques positifs","Distribution neuroanatomique logique","Comorbidités : sensibilité lumière/bruit/odeurs, troubles sommeil, fatigue, problèmes cognitifs"],a:2,e:"IASP 2021 facultatifs (nociplastique probable) : antécédents hypersensibilité + au moins 1 comorbidité (lumière, bruit, odeurs, sommeil, fatigue, cognition)."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les réflexes axonaux dans les fibres C :",o:["Inhibent la libération de médiateurs inflammatoires","Activent les récepteurs nmda centraux","Libèrent cgrp et substance p → inflammation neurogène"],a:2,e:"PA antidromiques dans fibres C → libération CGRP + SP en périphérie → vasodilatation + extravasation = inflammation neurogène."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'ibuprofène inhibe principalement :",o:["Les récepteurs opioïdes MOR","Les cyclooxygénases COX-1 et COX-2 → ↓ prostaglandines","Les canaux Nav périphériques"],a:1,e:"AINS classiques (ibuprofène, naproxène, diclofénac) = inhibiteurs non sélectifs COX-1 + COX-2 → ↓ PGE2 → ↓ sensibilisation nocicepteurs. Mécanisme découvert par Vane (1971, Prix Nobel)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La tDCS influence les neurotransmetteurs clés de la douleur en modifiant :",o:["Uniquement la substance P et le CGRP","Le glutamate, le GABA, la dopamine et la sérotonine","Uniquement les endorphines endogènes"],a:1,e:"tDCS → modifie glutamate + GABA + dopamine + sérotonine → réorganisation fonctionnelle des réseaux liés à la douleur (sensorimoteur + saillance)."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel est le potentiel seuil de déclenchement d'un potentiel d'action ?",o:["−55 mv","0 mv","−70 mv"],a:0,e:"Potentiel de repos = −70 mV. Seuil = −55 mV. Pic = +40 mV. Ces 3 valeurs sont fondamentales."},
{ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Dans l'ACT, l'action engagée signifie :",o:["Attendre la disparition de la douleur avant d'agir","Agir selon ses valeurs même quand la douleur est présente","Se concentrer uniquement sur la réduction de la douleur"],a:1,e:"Action engagée = agir selon valeurs personnelles MALGRÉ la douleur ≠ attendre qu'elle disparaisse."},
{ch:"Classification",label:"Classification",type:"direct",q:"La paresthésie se distingue de la dysesthésie par :",o:["Son origine uniquement centrale","Sa distribution dermatomique","Son caractère non désagréable"],a:2,e:"Paresthésie = anormale + NON désagréable. Dysesthésie = anormale + DÉSAGRÉABLE. Les deux peuvent être spontanées ou provoquées."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Dans la sensibilisation centrale, le déséquilibre excitateur/inhibiteur se traduit par :",o:["↑ opioïdes endogènes ET ↓ substance P","↑ GABA/glycine ET ↓ glutamate","↑ glutamate/SP/CGRP ET ↓ GABA/glycine"],a:2,e:"SC = ↑ transmission excitatrice (glutamate, SP, CGRP) + ↓ transmission inhibitrice (GABA, glycine) → hyperexcitabilité des neurones de projection."},
{ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La TCC (11 semaines) produit des changements neuroplastiques dans :",o:["Le cortex préfrontal dorsolatéral (cpfdl) bilatéral","Le cortex somatosensoriel primaire s1","Le ganglion de la racine dorsale"],a:0,e:"TCC → ↑ matière grise CPFdl bilatéral = neuroplasticité réversible → ↑ modulation descendante."},
{ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'auto-efficacité est définie comme :",o:["Le niveau de douleur perçu","La croyance en sa capacité à gérer la douleur malgré elle","La capacité physique réelle du patient"],a:1,e:"Auto-efficacité = CROYANCE (pas capacité réelle). ↑ auto-efficacité → ↓ handicap, ↑ adhésion kiné."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'échelle analgésique de l'OMS a été créée en 1986 pour :",o:["La douleur oncologique","La douleur chronique primaire non cancéreuse","La douleur neuropathique uniquement"],a:0,e:"Échelle OMS = douleur oncologique. Ne s'applique pas telle quelle à la douleur chronique primaire."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La mindfulness utilise quel type de pratique adapté à la douleur ?",o:["Séances de 2 heures quotidiennes de méditation profonde","Suppression active des pensées douloureuses","Pratiques courtes et fréquentes avec accent sur curiosité plutôt que relaxation"],a:2,e:"Mindfulness adaptée à la douleur : pratiques courtes + fréquentes + curiosité (≠ relaxation) + mouvement conscient + ancrage sensoriel. Éviter immersion profonde si traumatisme non traité."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Le principe de la 'quatrième marche' de l'échelle OMS concerne :",o:["Les techniques interventionnelles (blocages, radiofréquence, neuromodulation) pour douleur réfractaire","L'utilisation combinée de 4 analgésiques simultanément","Le passage obligatoire par les 3 premiers paliers avant toute intervention"],a:0,e:"4ème palier = extension pratique (non officielle OMS) : techniques interventionnelles pour douleur réfractaire. Intégré dans 'l'ascenseur analgésique' comme bouton 'insoutenable/réfractaire'."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"L'Espagne est le 4ème pays de l'UE pour la consommation de :",o:["Ibuprofène","Fentanyl","Tramadol"],a:1,e:"Baromètre 2022 : Espagne = 4ème plus grand consommateur de fentanyl (après États-Unis, Allemagne, Royaume-Uni). > 1000 décès par overdose d'opioïdes entre 2010-2017."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La réversibilité de la neuroplasticité dans la douleur chronique est démontrée par :",o:["L'impossibilité de régénérer les fibres C lésées","La permanence des modifications synaptiques","La récupération du volume de matière grise après traitement efficace"],a:2,e:"Études d'imagerie : récupération volume matière grise (amygdale, thalamus, CCA, insula) après traitement efficace et ↓ douleur chronique."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'affrontement actif contraste avec la gestion passive qui est caractérisée par :",o:["Dépendance aux médicaments, évitement des activités et résignation","Exercice physique et résolution de problèmes","Acceptation et engagement dans la vie malgré la douleur"],a:0,e:"Gestion passive = médicaments seuls + repos + évitement + résignation. Affrontement actif = exercice + autogestion + résolution de problèmes + objectifs significatifs."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La fibromyalgie représente en Espagne un coût de :",o:["50 millions d'euros par an (dont 90% de coûts directs)","11 millions d'euros par an (dont 66% de coûts indirects)","500 millions d'euros par an (uniquement hospitalisations)"],a:1,e:"Fibromyalgie (2,4% des Espagnols) = 11 millions €/an. 33% coûts directs (consultations). 66% coûts indirects (absentéisme). Âge moyen 49 ans = plein milieu de la vie active."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel ion entre dans la terminaison axonale pour libérer les neurotransmetteurs ?",o:["K⁺ via les kv","Ca²⁺ via les vocc","Na⁺ via les nav"],a:1,e:"PA → ouverture VOCC → entrée Ca²⁺ → fusion vésicules → libération neurotransmetteurs."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quelle est la durée d'un patch de fentanyl transdermique ?",o:["24 heures","72 heures (3 jours)","7 jours"],a:1,e:"Fentanyl transdermique = patch à changer toutes les 72h. Posologie initiale : 12-25 µg/h. Évaluation à 24h. Contre-indiqué sans tolérance opioïdes préalable et si fièvre > 39°C."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Dans le modèle enactif, les 'affordances' correspondent à :",o:["Les réseaux cérébraux de la douleur","Les médiateurs inflammatoires périphériques","Les opportunités d'action perçues en fonction des capacités et du contexte"],a:2,e:"'Affordances' (Stilwell 2019) = opportunités d'action que l'environnement offre à une personne selon ses capacités. La douleur chronique → monde perçu comme limité + menaçant → ↓ affordances."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La neuropathie des petites fibres (Small Fiber Neuropathy) se caractérise par :",o:["Anomalies caractéristiques à l'EMG conventionnel","Dysfonctionnement des fibres Aβ uniquement","Dysfonctionnement des fibres Aδ et C avec résultats EMG souvent NORMAUX"],a:2,e:"Small Fiber Neuropathy (SFN) = dysfonctionnement Aδ + C. EMG = normal (explore Aβ uniquement). Diagnostic : biopsie cutanée (densité fibres intra-épidermiques). 70% ont dysfonction vasculaire autonome."},
{ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le modèle peur-évitement montre que le catastrophisme mène à :",o:["Évitement, hypervigilance et handicap","Réduction automatique de la douleur","Confrontation et rétablissement rapide"],a:0,e:"Catastrophisme → peur → évitement + hypervigilance → handicap + dépression (Vlaeyen 1992)."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Les déterminants sociaux de la santé influencent la douleur chronique via :",o:["Uniquement le niveau d'éducation","Uniquement les facteurs génétiques héréditaires","Le statut socio-économique, l'accès aux soins, les conditions de travail et l'inclusion sociale"],a:2,e:"Karran et al. (J Pain 2022) : déterminants sociaux (socio-économique, accès soins, conditions travail, inclusion) → influencent directement l'expérience douloureuse et les résultats de santé."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La douleur chronique dans la CIM-11 est classée comme :",o:["Une maladie à part entière (et non uniquement un symptôme)","Une condition psychiatrique","Uniquement un symptôme d'une autre pathologie"],a:0,e:"Treede et al. (Pain 2019, IASP) : la douleur chronique dans CIM-11 peut être classée comme maladie à part entière (douleur chronique primaire) ou comme symptôme d'une autre maladie (douleur chronique secondaire)."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les récepteurs opioïdes (MOR, DOR, KOR) sont couplés à :",o:["Protéine gq → plc → excitation","Protéine gi → ↓ ampc → analgésie","Protéine gs → ↑ ampc → excitation"],a:1,e:"Opioïdes → Gi → ↓ AMPc → ↓ libération neurotransmetteurs excitateurs → analgésie."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La crème EMLA® est appliquée :",o:["En massage profond sur la zone douloureuse","12h ON / 12h OFF comme un patch","1g/10cm² sous occlusion 60 minutes avant ponction"],a:2,e:"EMLA (lidocaïne + prilocaïne) = analgésie cutanée pré-ponction. 1g/10cm² sous occlusion 60 min. Eviter chez nourrissons < 3 mois (méthémoglobinémie). Patch lidocaïne 5% = 12h ON/12h OFF."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Pourquoi les benzodiazépines sont à éviter en cas de syndrome d'apnée obstructive du sommeil (SAOS) sans traitement ?",o:["Elles aggravent la dépression respiratoire nocturne","Elles perturbent l'effet des opioïdes","Elles augmentent la kinésiophobie"],a:0,e:"BZD → dépression respiratoire + ↓ tonus musculaire → aggrave SAOS non traité → risque hypoxie nocturne. Utilisation ponctuelle uniquement."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le NGF est libéré par :",o:["Les interneurones de la corne dorsale","Les fibroblastes au niveau du site lésé","Les cellules de schwann"],a:1,e:"NGF = fibroblastes → récepteur TrkA → hyperalgésie + dégranulation mastocytes."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La péri-durale caudale est une voie d'injection :",o:["Par ponction directe du disque intervertébral","Par voie interlaminaire cervicale","Par le hiatus sacral — approche inférieure de l'espace épidural"],a:2,e:"Péri-durale caudale = hiatus sacral → espace épidural. Voies : interlaminaire, transforaminale, caudale. Indiquée : sciatique aiguë/sévère par hernie discale."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le taux de mortalité associé à l'isolement social est comparable à :",o:["Une légère hypertension artérielle","Boire 1-2 verres d'alcool par jour","La consommation de tabac ou l'obésité"],a:2,e:"Étude 308 849 sujets / 7,5 ans : isolement social → ↑ mortalité similaire à tabagisme + obésité. Montre l'impact biologique profond de la connexion sociale sur la santé."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La TCC peut entraîner une réduction considérable du catastrophisme :",o:["Uniquement en combinaison avec des opioïdes","Même chez des patients dont la douleur chronique persiste depuis des décennies","Uniquement si la douleur est récente (< 1 an)"],a:1,e:"TCC → ↓ catastrophisme significative même dans les douleurs chroniques de longue date. Effets durables (mois à années). Pas de besoin d'opioïdes pour son efficacité."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La prégabaline est contre-indiquée ou nécessite un ajustement en cas de :",o:["Insuffisance hépatique sévère","Épilepsie non contrôlée","Insuffisance rénale (clairance < 30 ml/min)"],a:2,e:"Gabapentinoïdes (gabapentine + prégabaline) = élimination rénale → ajuster si IRC. Insuffisance hépatique sévère → tapentadol. Épilepsie → tramadol contre-indiqué."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Les inhibiteurs sélectifs COX-2 (célécoxib) ont moins de gastropathie car :",o:["Ils épargnent la COX-1 qui protège la muqueuse gastrique","Ils activent les récepteurs opioïdes gastriques","Ils inhibent la production d'acide gastrique"],a:0,e:"COX-1 = constitutive → protège muqueuse gastrique. COX-2 = inductible → inflammation. COX-2 sélectifs → moins de gastropathie MAIS ↑ risque thrombotique car ↓ prostacycline."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel est le premier palier de l'échelle analgésique de l'OMS ?",o:["Opioïdes faibles : tramadol","Non-opioïdes : paracétamol et ains","Opioïdes forts : morphine"],a:1,e:"Palier 1 = non-opioïdes ± adjuvants. Palier 2 = opioïdes faibles. Palier 3 = opioïdes forts."},
{ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le Trauma Informed Care se base sur la question :",o:["Qu'est-ce qui ne va pas chez ce patient ?","Quelle technique appliquer ?","De quoi ce patient a-t-il besoin ?"],a:2,e:"TIC = 'De quoi ce patient a-t-il besoin ?' (≠ 'Qu'est-ce qui ne va pas ?'). 6 principes : sécurité, collaboration, autonomisation, confiance, considération, choix."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'ACT produit des effets moyens sur :",o:["La cicatrisation tissulaire (effets modérés)","L'intensité de la douleur (effets forts)","L'interférence de la douleur, la dépression et l'acceptation"],a:2,e:"ACT (méta-analyse 2024) : effets MOYENS sur interférence douleur + dépression + acceptation. Effets FAIBLES sur intensité douloureuse. Forts sur flexibilité psychologique."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Quel est le cluster diagnostique de la douleur neuropathique (Shraim 2021) ?",o:["Douleur diffuse + CSI ≥ 40 + facteurs psychosociaux","Douleur localisée + mécanique + absence de dysesthésies","Distribution dermatomique + antécédents lésion nerveuse + tests neurodynamiques positifs (Sensibilité 88,7%)"],a:2,e:"Cluster neuropathique (n=464) : distribution dermatomique (OR 12,64) + ATCD lésion nerveuse (OR 12,64) + tests neurodynamiques + (OR 14,64). Sensibilité 88,7%, Spécificité 76,6%."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel neurotransmetteur est impliqué dans l'analgésie via les récepteurs nicotiniques et muscariniques ?",o:["Sérotonine","Acétylcholine (ACh)","Dopamine"],a:1,e:"ACh = neurotransmetteur cholinergique central. Sa modulation via nAChR (nicotiniques) et mAChR (muscariniques) est impliquée dans l'analgésie."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel canal détecte les stimuli mécaniques et contribue à l'allodynie mécanique ?",o:["Piezo2","Trpv1","Asic"],a:0,e:"Piezo2 = mécanosensible → allodynie mécanique induite par inflammation ou lésion nerveuse."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Dans l'ACT, que signifie 'vivre selon ses valeurs' ?",o:["Agir conformément à ce qui est vraiment important pour soi malgré la douleur","Éviter toute activité qui pourrait augmenter la douleur","Accepter passivement la douleur sans chercher de traitement"],a:0,e:"ACT = accepter la douleur + agir selon ses valeurs personnelles. Ce n'est pas de la résignation mais un engagement actif dans une vie qui a du sens malgré la douleur."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Dans le modèle de l'organisme mature, les 'outputs' comprennent :",o:["Uniquement la réponse douloureuse consciente","Réponses somatiques, autonomes, neuroendocrines, neuro-immunes et comportementales","Les signaux sensoriels périphériques entrants"],a:1,e:"MOM (Gifford) : Input (signaux sensoriels + contexte) → Processing (conscient/inconscient, croyances, émotions) → Output (réponses somatiques + autonomes + neuroendocrines + neuro-immunes + comportementales)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel est l'effet principal de l'exercice sur le système sympathique dans la douleur chronique ?",o:["Aucun effet sur le système sympathique","Normalisation du tonus sympathique et réduction de l'hypervigilance","Augmentation du tonus sympathique pour stimuler la guérison"],a:1,e:"Exercice → normalisation du tonus sympathique + ↓ état d'hypervigilance + ↓ réponse au stress → contribue à la désensibilisation centrale."},
{ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le catastrophisme comporte 3 composantes. Lesquelles ?",o:["Anxiété, dépression, hypervigilance","Rumination, impuissance, magnification","Évitement, kinésiophobie, désespoir"],a:1,e:"PCS (Sullivan) = rumination + impuissance + magnification. Seuil ≥ 30."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"L'amélioration du catastrophisme dans les traitements actifs représente :",o:["100% des bénéfices — c'est le seul mécanisme d'action","35 à 40% des bénéfices du traitement sur la réduction de la douleur et du handicap","Moins de 5% — un facteur négligeable"],a:1,e:"Même dans les interventions kinésithérapiques d'exercice qui ne ciblent pas explicitement le catastrophisme, 35-40% des bénéfices passent par sa réduction (Leeuw 2008, Smeets 2006)."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"L'activité de la CPFm (cortex préfrontal médian) dans la douleur chronique est positivement corrélée à :",o:["La réduction du catastrophisme","L'amélioration de l'auto-efficacité","L'intensité de la douleur et au développement de la douleur spontanée"],a:2,e:"Apkarian et al. 2011 : activité CPFm positivement corrélée à intensité + développement douleur spontanée chez patients lombalgiques chroniques (variation 70-80%)."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les récepteurs GABA-B sont des récepteurs :",o:["Ionotropiques → sortie de K⁺","Métabotropiques (GPCR) → inhibition présynaptique","Ionotropiques → entrée de Cl⁻"],a:1,e:"GABA-A = ionotropique → Cl⁻ → inhibition post-synaptique rapide. GABA-B = métabotropique (GPCR) → inhibition pré et post-synaptique lente."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les interneurones de la corne dorsale jouent un rôle de :",o:["Transmission directe vers le thalamus","Relais entre neurones afférents et efférents","Modulation supraspinale de la douleur"],a:1,e:"Interneurones = relais entre afférents (fibres C, Aδ) et efférents. Peuvent être excitateurs ou inhibiteurs. Leur perte (désinhibition GABAergique) → allodynie."},
{ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"On interrompt le patient en moyenne après :",o:["10 secondes","23 secondes","45 secondes"],a:1,e:"Marvel et al. (1999) : 23 secondes. Le patient a besoin de 2 minutes max pour répondre à une question ouverte."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quelle est l'indication principale de la mindfulness dans la matrice de décision ?",o:["Évitement rigide avec paralysie par analyse","Catastrophisme élevé avec kinésiophobie","Douleur chronique avec stress élevé, insomnie et rumination"],a:2,e:"Matrice : TCC = catastrophisme + kinésiophobie. ACT = évitement rigide + paralysie. Mindfulness = stress élevé + insomnie + rumination."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Lors de la dépolarisation, quel ion entre massivement dans la cellule ?",o:["K⁺","Na⁺","Ca²⁺"],a:1,e:"Entrée rapide Na⁺ via canaux Nav → dépolarisation jusqu'à +40 mV. K⁺ sort lors de repolarisation."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le récepteur NMDA nécessite pour s'activer :",o:["Glutamate uniquement","Substance p uniquement","Glutamate + glycine"],a:2,e:"NMDA-R = double serrure : glutamate + glycine obligatoires. Central dans wind-up et sensibilisation centrale."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La sensibilisation périphérique se manifeste cliniquement par :",o:["Hyperalgésie secondaire dans les zones adjacentes","Hyperalgésie primaire sur le site de la lésion","Allodynie en dehors du site lésé"],a:1,e:"Sensibilisation périphérique → hyperalgésie PRIMAIRE (sur le site). Hors site = sensibilisation CENTRALE."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le GABA exerce un effet :",o:["Excitateur via sortie de k⁺","Excitateur via entrée de na⁺","Inhibiteur via entrée de cl⁻"],a:2,e:"GABA-A → entrée Cl⁻ → hyperpolarisation → inhibition. Désinhibition GABAergique = mécanisme de chronicisation."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Les fonctions cognitives exécutives chez les patients douloureux chroniques sont :",o:["Non affectées par la douleur chronique","Augmentées pour compenser la douleur","Considérablement diminuées (preuves modérées à fortes), corrélées négativement à la sévérité de la douleur"],a:2,e:"Bunk et al. (2019) : N=81 études. Fonctions cognitives exécutives (mémoire de travail, flexibilité, inhibition, planification) = considérablement diminuées dans la douleur chronique."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les nocicepteurs silencieux :",o:["Transmettent uniquement les stimuli thermiques","Sont actifs en permanence","S'activent uniquement en conditions pathologiques (inflammation, lésion)"],a:2,e:"Nocicepteurs silencieux = inactifs au repos. Réveillés par inflammation → hyperalgésie + sensibilisation centrale."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les noyaux parabrachiens (PBN) jouent un rôle de :",o:["Centre de la modulation descendante inhibitrice","Station relais principale de la voie spinothalamique latérale","Centre relais vers l'amygdale pour les aspects émotionnels de la douleur"],a:2,e:"PBN = régulateur clé douleur neuropathique. Projections vers amygdale → aspects émotionnels/mémoire de la douleur."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel est le rôle de l'amygdale centrale (CeA) dans la douleur ?",o:["Aspects émotionnels négatifs de la douleur","Localisation et intensité (discriminatif)","Modulation descendante inhibitrice"],a:0,e:"Amygdale centrale (CeA) = aspects émotionnels négatifs. Amygdale basolatérale (BLA) = mémoire de la peur + informations sensorielles polymodales."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La désinhibition GABAergique peut provoquer :",o:["Analgésie par activation opioïdes endogènes","Hyperalgésie mécanique et allodynie","Réduction du wind-up par blocage nmda"],a:1,e:"Perte interneurones GABAergiques → désinhibition → hyperexcitabilité neurones de projection → allodynie + hyperalgésie."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les nocicepteurs mécaniques répondent à :",o:["Températures extrêmes uniquement","Pressions intenses, déformations, piqûres, coupures","Substances chimiques libérées lors d'inflammation"],a:1,e:"Nocicepteurs mécaniques = pressions intenses + déformations + piqûres + coupures. Transmettent via Aδ → signal rapide dont la réponse augmente avec l'intensité du dommage."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La codéine est un opioïde faible qui agit :",o:["Directement sur les récepteurs MOR sans métabolisation","En inhibant la recapture de sérotonine","En étant convertie en morphine par le CYP2D6 hépatique"],a:2,e:"Codéine = prodrogue → métabolisée en morphine par CYP2D6. Les 'métaboliseurs lents' (génétique) ont peu d'effet analgésique. Les 'ultra-métaboliseurs' risquent une toxicité à la morphine."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'alliance thérapeutique est un facteur prédictif indépendant des résultats cliniques car :",o:["Elle remplace entièrement l'effet de la technique","Elle n'a d'effet que sur la satisfaction du patient, pas sur la douleur","Son influence peut être aussi importante que la technique appliquée"],a:2,e:"Alliance thérapeutique = prédicteur indépendant des résultats musculo-squelettiques. Influence parfois aussi importante que la technique (McParlin et al. 2022)."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La substance P active principalement quel récepteur ?",o:["Nmda-r","Ampa-r","Nk1"],a:2,e:"Substance P → NK1. Présent dans 80% des neurones de projection → contribue au wind-up."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les orexines (hypocrétines) ont des effets :",o:["Excitateurs sur les récepteurs NMDA","Pro-nociceptifs → ↑ substance P","Antinociceptifs au niveau spinal et supraspinal"],a:2,e:"Orexines = peptides qui exercent des effets antinociceptifs au niveau spinal et supraspinal via récepteurs orexine 1 et 2."},
{ch:"Classification",label:"Classification",type:"direct",q:"Le modèle enactif considère la douleur comme :",o:["Un signal purement biologique du tissu lésé","Un phénomène uniquement cérébral","Une propriété émergente de l'interaction personne-environnement"],a:2,e:"Modèle enactif (Stilwell 2019) : douleur = propriété émergente corps-esprit-environnement. Concept clé : 'affordances"},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les fibres C sont :",o:["Myélinisées, rapides, uniquement thermiques","Non myélinisées, rapides, mécaniques","Non myélinisées, lentes (~2 m/s), polymodales"],a:2,e:"Fibres C : non myélinisées, < 2 µm de diamètre, ~2 m/s, polymodales (méca + thermo + chimique)."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"En physiothérapie invasive, l'objectif thérapeutique principal est :",o:["Déclencher le wind-up","Favoriser la ltd (dépression à long terme)","Favoriser la ltp"],a:1,e:"LTD = ↓ efficacité synaptique → désensibilisation. Stimuli 2–10 Hz faible intensité. Objectif = ↓ sensibilisation."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La bupivacaïne infiltrée est plus cardiotoxique que la lidocaïne car :",o:["Elle se lie plus fortement et plus durablement aux canaux Nav cardiaques","Elle active les récepteurs opioïdes cardiaques","Elle inhibe la COX-2 cardiaque"],a:0,e:"Bupivacaïne = anesthésique local puissant et longue durée. Cardiotoxicité ↑ car liaison forte/durable aux Nav cardiaques. Max 2 mg/kg. Lidocaïne max 4,5 mg/kg (sans adrénaline)."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Les patients souffrant de douleur chronique en Espagne : quel pourcentage consulte en soins primaires ?",o:["50%","30%","88,2%"],a:2,e:"59,3% ont consulté un professionnel au cours du dernier mois : 88,2% en soins primaires, 71,5% en urgences. Seulement 15% sont suivis par un spécialiste douleur."},
{ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Les drapeaux roses représentent :",o:["Des signes d'alarme nécessitant une imagerie","Des facteurs de risque de chronicisation","Des facteurs psychosociaux protecteurs contre la chronicisation"],a:2,e:"Drapeaux roses = PROTECTEURS (Gifford). Drapeaux jaunes = risque (catastrophisme, peur-évitement)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel est le délai recommandé avant de reprendre les exercices excentriques sous fluoroquinolones ?",o:["Au moins 4 semaines après la fin du traitement","Pas de délai nécessaire si pas de douleur","48 heures après la dernière prise"],a:0,e:"Fluoroquinolones → ↑ risque tendinopathie/rupture. Éviter exercices excentriques membres inférieurs pendant AU MOINS 4 semaines après traitement. Signaler douleur soudaine au mollet/cheville."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quelle est la contre-indication principale des AINS classiques en fin de grossesse ?",o:["Ils sont autorisés tout au long de la grossesse","1er trimestre uniquement","3ème trimestre de grossesse (risque de fermeture prématurée du canal artériel)"],a:2,e:"AINS contre-indiqués au 3ème trimestre : risque fermeture prématurée canal artériel + réduction du liquide amniotique. Aussi : IRC stade 4-5, ulcère peptique actif, IC NYHA III-IV."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Le tapentadol est indiqué dans :",o:["La douleur neuropathique mixte","La douleur chronique primaire sans composante neuropathique","La douleur nociceptive aiguë légère"],a:0,e:"Tapentadol = double mécanisme : agoniste opioïde + inhibiteur recapture NE. Indiqué : douleur modérée à sévère + composante neuropathique mixte."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"L'oxyde nitrique (NO) dans la nociception :",o:["Inhibe directement les nocicepteurs périphériques","Bloque les canaux TRPV1","Se diffuse dans d'autres neurones et stimule l'activation du NMDA-R"],a:2,e:"NO = molécule gazeuse mobile → diffuse entre neurones → active seconds messagers → rôle crucial dans transmission nociceptive post-inflammatoire + stimule NMDA-R."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quel processus de l'ACT aide à réduire l'impact de la pensée 'mon dos est fragile' ?",o:["La défusion cognitive — observer la pensée sans la prendre pour un fait","L'acceptation — accepter que le dos soit fragile","L'action engagée — agir malgré la pensée"],a:0,e:"Défusion cognitive = voir 'mon dos est fragile' comme une PENSÉE (événement mental), pas comme un fait. Le patient peut alors bouger MÊME SI la pensée est là. ≠ accepter que c'est vrai."},
{ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Le nocebo est produit par :",o:["Activation des endocannabinoïdes","Activation de la cck et désactivation des opioïdes endogènes","Activation des opioïdes endogènes et dopamine"],a:1,e:"Nocebo → CCK + désactivation opioïdes endogènes → ↑ douleur. Déclenché par messages alarmistes."},
 {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Dans l'ACT, le 'moi observateur' correspond à :",o:["La capacité à observer ses propres pensées et émotions sans s'y identifier","L'auto-critique systématique des pensées négatives","La suppression des pensées douloureuses"],a:0,e:"Moi observateur (ACT) = perspective de l'observateur → observer pensées + émotions sans s'y identifier. Permet la défusion cognitive."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le modèle peur-évitement implique que la 'confrontation' mène au :",o:["Aggravation de la douleur par surcharge","Rétablissement par maintien des activités et réduction de la peur","Même pronostic que l'évitement"],a:1,e:"Confrontation (Vlaeyen) = 'je vais bien, je vais m'en sortir' → maintien activités → ↓ peur → rétablissement. Évitement → hypervigilance → handicap → chronicisation."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'étoricoxib (COX-2 sélectif) est contre-indiqué en cas de :",o:["Douleur articulaire légère","Cardiopathie ischémique et antécédent d'AVC","Gastropathie à risque élevé"],a:1,e:"COX-2 sélectifs = ↑ risque thrombotique (↓ prostacycline). Contre-indiqués : cardiopathie ischémique + IC + ATCD AVC + IRC avancée. Indiqués : arthrose avec ↑ risque GI."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le catastrophisme est associé à un risque accru de :",o:["Abus d'opioïdes sur ordonnance","Guérison spontanée rapide","Réponse positive aux interventions chirurgicales"],a:0,e:"Catastrophisme prédit (Martel 2013) : ↑ risque abus opioïdes ordonnance. Aussi prédit : retour au travail difficile, idées suicidaires, intensité douleur, réponses cérébrales nocives."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le canal TRPA1 est activé par :",o:["La chaleur > 42°C et la capsaïcine","Les stimuli mécaniques exclusivement","Le froid intense, les irritants et les toxines"],a:2,e:"TRPA1 = froid intense + irritants + toxines + produits chimiques. TRPV1 = chaleur > 42°C + protons + capsaïcine. TRPV1 et TRPA1 sont tous deux importants dans la douleur neuropathique."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La TCC est particulièrement indiquée en cas de :",o:["Stress élevé avec insomnie et rumination","Catastrophisme élevé, peur du mouvement et faible auto-efficacité","Évitement rigide et paralysie par analyse"],a:1,e:"TCC = catastrophisme + kinésiophobie + ↓ auto-efficacité. ACT = évitement rigide + paralysie. Mindfulness = stress + insomnie + rumination."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La radiofréquence doit être précédée de :",o:["Un test cardiovasculaire","Une irm lombaire","Un blocage diagnostique des branches médiales positif"],a:2,e:"Blocage diagnostique positif obligatoire avant RF. Efficacité 6–12 mois. Sans sélection = résultats hétérogènes."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La zona tegmentale ventrale (VTA) dans la douleur neuropathique chronique :",o:["Inhibe systématiquement la douleur","Les neurones dopaminergiques présentent une plasticité","Constitue le centre primaire de la nociception"],a:1,e:"VTA = neurones dopaminergiques → plasticité dans douleur neuropathique chronique. Impliqué dans la récompense et la motivation → lien douleur/affect négatif."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Dans quel ordre se produisent les étapes du processus nociceptif ?",o:["Transmission → Transduction → Modulation → Perception","Perception → Transduction → Transmission → Modulation","Transduction → Transmission → Modulation → Perception"],a:2,e:"Étapes : 1) Transduction (stimulus → signal électrique en périphérie), 2) Transmission (périphérie → moelle → cerveau), 3) Modulation (amplification ou inhibition), 4) Perception (expérience consciente)."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Dans le cluster clinique de la douleur nociplastique (Shraim 2021), quel OR (odds ratio) a le critère 'zones diffuses ou non anatomiques' ?",o:["OR 27,57","OR 69,79","OR 4,25"],a:0,e:"Cluster nociplastique (n=464, Sensibilité 91,8%, Spécificité 97,7%) : douleur disproportionnée (OR 15,19) + schéma non mécanique (OR 30,69) + zones diffuses/non anatomiques (OR 27,57) + facteurs psychosociaux (OR 7,65)."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le noyau VPL du thalamus reçoit les informations de :",o:["La voie spinothalamique médiale (aspects affectifs)","La voie spinothalamique latérale (aspects discriminatifs)","Les noyaux parabrachiens (aspects émotionnels)"],a:1,e:"VPL = spinothalamique latérale → localisation + intensité (discriminatif). Noyaux médians = affectif/motivationnel."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quelle est la différence principale entre radiofréquence conventionnelle et pulsée ?",o:["Conventionnelle = lésion thermique. Pulsée = neuromodulatrice sans destruction thermique","Conventionnelle = pulsée mais plus lente","Pulsée = lésion thermique plus étendue"],a:0,e:"RF conventionnelle = lésion thermique → destruction du nerf. RF pulsée = non thermique → neuromodulation → pas de destruction. RF refroidie = lésion thermique mais volume plus grand."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le ganglion trigéminal contient les corps cellulaires des neurones sensoriels afférents pour :",o:["Les organes viscéraux","Le reste du corps","La tête et le visage"],a:2,e:"Ganglion trigéminal (GT) = tête + visage. Ganglion de la racine dorsale (GRD) = reste du corps. Ganglion nodulaire = nerf vague (viscères)."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le phénomène de wind-up est une forme de plasticité :",o:["Irréversible","À court terme","À long terme (comme la LTP)"],a:1,e:"Wind-up = plasticité à COURT terme : même stimulus répété → réponse progressivement plus intense. ≠ LTP (long terme). Le wind-up peut préparer le terrain à la LTP."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les nocicepteurs thermiques s'activent à partir de :",o:["Chaleur > 37°C ou froid < 10°C","Chaleur > 42°C ou froid < 5°C","Chaleur > 50°C uniquement"],a:1,e:"Nocicepteurs thermiques : chaleur nociceptive > 42°C (comme brûlures) et froid nociceptif < 5°C (comme engelures). Entre les deux = températures non nociceptives."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Lors d'une lésion tissulaire, les nocicepteurs silencieux :",o:["Diminuent leur activité pour protéger les tissus","Inhibent les nocicepteurs mécaniques adjacents","Sont 'réveillés' et deviennent mécanosensibles — amplifient les informations nocives"],a:2,e:"Nocicepteurs silencieux normalement inactifs → dans conditions pathologiques (inflammation) → 'réveillés' par substances inflammatoires → deviennent mécanosensibles → ↑ transmission nociceptive."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La 'soupe inflammatoire' est libérée par :",o:["Les cellules endommagées ou inflammatoires au site de la lésion","Les neurones de la corne dorsale","La substance grise périaqueducale"],a:0,e:"'Soupe inflammatoire' = bradykinine + PGE2 + NGF + ATP + H⁺ + histamine + 5-HT + SP + CGRP → libérés au site lésionnel → sensibilisation périphérique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La prégabaline a des effets indésirables principaux de :",o:["Xérostomie et constipation","Vertiges et vision trouble","Nausées et hypertension artérielle"],a:1,e:"Prégabaline : vertiges + vision trouble + somnolence. Gabapentine : somnolence + œdème + prise de poids. Duloxétine : nausées + transpiration + HTA. Amitriptyline : xérostomie + somnolence + prise de poids."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Lors de l'hyperpolarisation post-PA, quel phénomène se produit ?",o:["Entrée de Na⁺ → re-dépolarisation","Entrée de Ca²⁺ → libération de neurotransmetteurs","Sortie continue de K⁺ → potentiel membranaire plus négatif que le repos"],a:2,e:"Après repolarisation, les canaux Kv restent ouverts → sortie K⁺ → hyperpolarisation transitoire (potentiel plus négatif que −70 mV). Ensuite la pompe Na⁺/K⁺ rétablit le repos."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quelle est la vitesse de conduction approximative des fibres C ?",o:["~2 m/s","~20 m/s","~70 m/s"],a:0,e:"Fibres C : ~2 m/s (lentes, non myélinisées). Fibres Aδ : ~5-30 m/s. Fibres Aβ : ~30-70 m/s."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Dans le modèle peur-évitement, quelles informations alimentent le catastrophisme ?",o:["L'intensité de la douleur initiale uniquement","Expériences négatives antérieures, diagnostics alarmants, résultats d'imagerie, informations d'autres personnes","Uniquement les résultats d'imagerie médicale"],a:1,e:"Vlaeyen : sources du catastrophisme = expériences antérieures + divers avis médicaux + diagnostics + imagerie + informations de personnes de confiance → cognitions catastrophiques."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Un kiné utilise des mots comme 'votre dos est détruit', 'vos disques sont usés'. Quel effet cela peut-il provoquer ?",o:["Aucun effet neurobiologique mesurable","Effet placebo : le patient est informé et se sent mieux","Effet nocebo : activation CCK → ↓ opioïdes endogènes → ↑ douleur"],a:2,e:"Messages alarmistes → nocebo → CCK → désactivation opioïdes endogènes → hyperalgésie. Les paroles du kiné ont un effet neurobiologique RÉEL et mesurable."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La définition de la douleur par Williams et Craig (2016) comprend :",o:["3 composantes : biologique, psychologique et sociale","2 composantes : sensorielle et émotionnelle","4 composantes : sensorielle, émotionnelle, cognitive et sociale"],a:2,e:"Williams & Craig 2016 : 'douleur pénible associée à une lésion réelle ou potentielle, avec composantes sensorielles, émotionnelles, cognitives et sociales.'"},
  {ch:"Classification",label:"Classification",type:"direct",q:"Selon Muhammad Yunnus (2008), les termes 'symptômes sans explication médicale' et 'somatisation' doivent être :",o:["Remplacés par 'douleur fonctionnelle'","Utilisés uniquement par les psychiatres","Abandonnés — le dualisme maladie-pathologie n'a aucun fondement rationnel actuel"],a:2,e:"Yunnus 2008 : 'Le début d'une nouvelle ère' — abandon du dualisme maladie-pathologie. Ces termes nuisent à la communication patient-thérapeute et à la qualité des soins."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le système nerveux viscéral surveille :",o:["Les stimuli externes comme la lumière et le toucher","Le fonctionnement des organes, la pression artérielle et la température interne","La position du corps dans l'espace"],a:1,e:"SNP viscéral = états physiologiques internes (organes, PA, T°). SNP somatosensoriel = stimuli externes (toucher, température, lumière, odeurs)."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le noyau paraventriculaire (PVT) du thalamus peut :",o:["Jouer un rôle uniquement dans la proprioception","Inhiber la douleur systématiquement","Faciliter la douleur via certaines projections thalamiques"],a:2,e:"Le thalamus n'est pas qu'un relais passif. Le noyau PVT peut faciliter la douleur via certaines projections. Le thalamus reçoit aussi des entrées corticales modulatrices."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel opioïde est particulièrement dangereux si le patient a de la fièvre > 39°C ?",o:["Morphine orale","Fentanyl transdermique","Tramadol"],a:1,e:"Fentanyl transdermique : fièvre → ↑ absorption cutanée → surdosage potentiel. Aussi : chaleur externe (bouillotte, bain)."},
  {ch:"Classification",label:"Classification",type:"direct",q:"L'hypoalgésie est définie comme :",o:["Perception anormalement exagérée face à un stimulus nociceptif","Perception douloureuse face à un stimulus non nociceptif","Perception réduite de la douleur face à un stimulus nociceptif"],a:2,e:"Hypoalgésie = ↓ perception douloureuse face à stimulus nociceptif. Allodynie = douleur sur stimulus NON nociceptif. Hyperalgésie = ↑ réponse à stimulus nociceptif."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quelle technique de physiothérapie invasive utilise des fréquences 2-10 Hz pour favoriser la LTD ?",o:["Ponction sèche mécanique seule","Électropuncture / neuromodulation percutanée à basse fréquence","Radiofréquence conventionnelle"],a:1,e:"Électropuncture + neuromodulation percutanée : 2-10 Hz + impulsions longues → favorise LTD → ↓ excitabilité synaptique → désensibilisation. Radiofréquence = technique interventionnelle (unité douleur)."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le potentiel de repos d'un neurone typique est de :",o:["+40 mv","−70 mv","−55 mv"],a:1,e:"−70 mV = repos. −55 mV = seuil du PA. +40 mV = pic de dépolarisation."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La souffrance se distingue de la douleur car elle :",o:["Est uniquement d'origine psychologique","Est toujours plus intense que la douleur","Menace l'intégrité et l'identité personnelle de l'individu"],a:2,e:"Souffrance = expérience extrêmement négative menaçant l'intégrité + l'identité personnelle. Douleur = expérience sensorielle + émotionnelle. La souffrance inclut : honte, culpabilité, ennui, épuisement."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quelle zone corticale traite l'aspect affectif et cognitif de la douleur ?",o:["Cortex somatosensoriel primaire (s1)","Cortex cingulaire antérieur (cca)","Cortex préfrontal dorsolatéral"],a:1,e:"CCA = affectif + cognitif. S1/S2 = discriminatif. CPFdl = modulation descendante."},
{ch:"Classification",label:"Classification",type:"direct",q:"La douleur nociplastique se caractérise par :",o:["Localisée, mécanique, proportionnée, sans dysesthésies","Diffuse, disproportionnée, csi ≥ 40, sans lésion évidente","Distribution neuroanatomique logique et tests neurodynamiques +"],a:1,e:"Nociplastique = triade diffuse + disproportionnée + CSI ≥ 40. Ex : fibromyalgie. Altération nociception SANS lésion."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Pourquoi retirer un patch avant la diathermie ?",o:["La diathermie inactive le principe actif","La chaleur ↑ l'absorption cutanée et risque de brûlure","Le champ électromagnétique déplace le patch"],a:1,e:"Diathermie/ultrasons → chaleur locale → ↑ absorption cutanée (risque surdosage) + brûlure sous patch."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'effet placebo analgésique peut être :",o:["Uniquement produit par une substance pharmacologique inactive","Conditionné (appris) même sans substance active si le contexte est favorable","Inexistant si le patient sait qu'il reçoit un placebo"],a:1,e:"Placebo conditionné = cerveau apprend à associer contexte → analgésie. Des études montrent que même en sachant qu'on reçoit un placebo (open-label), des effets analgésiques persistent."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La bradykinine (BK) est un médiateur inflammatoire qui :",o:["Se lie aux récepteurs B1/B2 des nocicepteurs → pro-nociceptif","Active directement les récepteurs NMDA centraux","Inhibe la libération de prostaglandines"],a:0,e:"Bradykinine → récepteurs B1 et B2 → pro-nociceptif + sensibilisation des nocicepteurs. Fait partie de la 'soupe inflammatoire'."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le PHQ-9 est un questionnaire qui évalue :",o:["La kinésiophobie","La sensibilisation centrale","Les symptômes dépressifs (seuil modéré = 10-14)"],a:2,e:"PHQ-9 = dépression. Scores : 1-4 minimal, 5-9 léger, 10-14 modéré, 15-19 modérément grave, 20-27 grave. TSK = kinésiophobie. CSI = sensibilisation centrale. PCS = catastrophisme."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Le modèle biomédical considère la douleur comme :",o:["Une expérience subjective multidimensionnelle","Proportionnelle à la nature et l'étendue de la lésion tissulaire","Une propriété émergente de l'interaction personne-environnement"],a:1,e:"Modèle biomédical (XIXe s.) : douleur proportionnelle à la lésion. 'Douleur réelle/organique' ≠ 'douleur fonctionnelle/psychogène'. Ce dualisme est réfuté par les données scientifiques actuelles."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quel est l'effet des orexines sur la nociception ?",o:["Aucun effet connu sur la nociception","Effets pro-nociceptifs via activation des fibres C","Effets antinociceptifs au niveau spinal et supraspinal"],a:2,e:"Orexines = peptides hypothalamiques → effets antinociceptifs au niveau spinal + supraspinal via récepteurs orexine 1 et 2."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le Trauma Informed Care vise à :",o:["Créer des espaces sûrs et respectueux pour faciliter l'accès aux soins des patients traumatisés","Traiter directement les traumatismes psychologiques (rôle du kiné)","Éviter tout contact physique avec les patients traumatisés"],a:0,e:"TIC = créer espaces sûrs + accès précoce (plus rentable) + renforcer l'autonomie + outils d'autogestion. L'objectif n'est PAS de traiter le trauma (rôle des profes. de santé mentale) mais de minimiser les obstacles."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel peptide opioïde endogène se lie préférentiellement aux récepteurs MOR ?",o:["La dynorphine","Les enképhalines","Les endorphines (β-endorphine)"],a:2,e:"β-endorphine → MOR (préférentiel). Enképhalines → DOR. Dynorphine → KOR. Tous inhibent la libération de neurotransmetteurs excitateurs."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La voie spinothalamique antérieure (médiale) transmet :",o:["La perception émotionnelle et autonome désagréable de la douleur","La localisation précise et l'intensité","Les informations proprioceptives"],a:0,e:"Voie spinothalamique antérieure/médiale → thalamus médial → aspects émotionnels-autonomes. Voie latérale → noyau VPL → aspects discriminatifs."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quelle structure est un régulateur clé de la douleur neuropathique et relaie vers l'amygdale ?",o:["Noyaux intralaminaires du thalamus","Noyaux parabrachiens (PBN)","Cortex insulaire"],a:1,e:"PBN = régulateur clé douleur neuropathique + centre de relais vers l'amygdale pour les informations nociceptives. Cible principale des projections de la lame I spinale."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La communication verbale non menaçante du kiné :",o:["N'a aucun effet sur la perception de la douleur","Augmente la dépendance passive du patient","Réduit le catastrophisme et la kinésiophobie du patient"],a:2,e:"Langage non menaçant ('tissus solides', 'mouvement sûr', 'capacité d'adaptation') → ↓ catastrophisme + kinésiophobie → ↑ auto-efficacité. Les mots du kiné ont un effet neurobiologique réel."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le thalamus reçoit les informations nociceptives :",o:["En premier parmi les structures supraspinales","En même temps que l'amygdale","Après le cortex cingulaire antérieur"],a:0,e:"Voie ascendante : moelle épinière → thalamus (station relais) → S1/S2, CCA, insula, CPF."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les cellules gliales libèrent lors de la sensibilisation centrale :",o:["Gaba et glycine","Il-1β, tnf-α, il-6 et glutamate","Endorphines et encéphalines"],a:1,e:"Microglies + astrocytes → IL-1β, TNF-α, IL-6, ATP, glutamate → exacerbent la douleur."},
{ch:"Classification",label:"Classification",type:"direct",q:"La douleur chronique se définit comme :",o:["Une douleur d'intensité > 7/10","Une douleur persistant plus de 3 à 6 mois","Une douleur causée par une sensibilisation centrale"],a:1,e:"Douleur chronique = > 3–6 mois (Merskey 1994, Raja 2020). Définition temporelle ≠ mécanistique."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La mindfulness améliore la douleur en réduisant :",o:["Directement l'intensité du signal nociceptif périphérique","La réactivité émotionnelle à la douleur (moins de souffrance secondaire)","La libération de substance P au niveau de la corne dorsale"],a:1,e:"Mindfulness → ↓ réactivité émotionnelle (souffrance secondaire) + ↓ rumination + ↑ régulation autonome. Ne supprime pas la douleur mais change la RELATION avec elle."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Les fluoroquinolones augmentent le risque de :",o:["Arthralgies diffuses","Myalgie et myopathie","Tendinopathie et rupture tendineuse"],a:2,e:"Fluoroquinolones → tendinopathie/rupture (surtout tendon d'Achille). Éviter exercices excentriques 4 semaines."},
{ch:"Classification",label:"Classification",type:"direct",q:"L'allodynie est définie comme :",o:["Absence de douleur face à un stimulus nociceptif","Douleur provoquée par un stimulus normalement non douloureux","Réponse exagérée à un stimulus douloureux"],a:1,e:"Allodynie = douleur sur stimulus NON nociceptif. Hyperalgésie = réponse exagérée à stimulus nociceptif."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La PGE2 sensibilise les nocicepteurs via :",o:["↑ ampc → activation pka → phosphorylation nav et trpv1","Blocage direct des canaux nmda-r","Activation gi → ↓ ampc → analgésie"],a:0,e:"PGE2 → récepteurs EP → ↑ AMPc → PKA → phosphorylation Nav + TRPV1 → ↓ seuil d'activation."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le wind-up est médié par :",o:["Ampa-r et gaba","Récepteurs opioïdes et cannabinoïdes","Nmda-r et nk1"],a:2,e:"Wind-up = plasticité court terme : NMDA-R (glutamate) + NK1 (substance P) dans la corne dorsale."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Dans le modèle du triple réseau, l'hyperconnectivité entre S1 et le RND dans la douleur chronique signifie :",o:["Le traitement cognitif de la douleur s'améliore","La douleur s'intègre dans le concept de soi — elle devient partie de l'identité du patient","La localisation de la douleur s'améliore"],a:1,e:"Hyperconnectivité S1/RND → la douleur devient centrale dans l'identité du patient ('je suis un malade chronique'). Explique pourquoi le concept de soi change dans la douleur chronique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Dans quel cas la thérapie manuelle orthopédique (TMO) réduit-elle la douleur ?",o:["En activant les mécanorécepteurs → modulation de l'interprétation de la douleur + ↓ excitabilité corne dorsale","En réparant directement les structures lésées","En bloquant la transmission spinothalamique"],a:0,e:"TMO = stimulus mécanique et sensoriel → active mécanorécepteurs → ↓ excitabilité neurones nociceptifs corne dorsale + ↓ activité zones cérébrales de la menace + ↓ tonus sympathique."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le syndrome de stress post-traumatique (SSPT) est :",o:["Une conséquence uniquement de la douleur chronique","Un facteur protecteur contre la sensibilisation centrale","Un facteur de risque de douleur chronique et de transition aiguë → chronique"],a:2,e:"SSPT = facteur de risque de douleur chronique (Jenewein 2009) + transition aiguë → chronique + gravité élevée de la douleur chez les victimes d'abus."},
  {ch:"Classification",label:"Classification",type:"direct",q:"L'algorithme de Pain in Motion (Nijs 2016) permet de :",o:["Identifier le mécanisme prédominant de la douleur musculo-squelettique","Mesurer l'intensité douloureuse sur une échelle validée","Calculer la posologie exacte des antalgiques"],a:0,e:"Algorithme Nijs 2016 : classification clinique pour identifier mécanisme prédominant → neuropathique vs nociplastique vs nociceptive → guide l'approche thérapeutique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'exercice thérapeutique normalise :",o:["La composition du liquide céphalo-rachidien","Uniquement la force musculaire périphérique","Les cartes corticales altérées par la douleur persistante"],a:2,e:"Exercice → normalisation cartes corticales altérées + ↓ sensibilisation centrale + ↑ modulation descendante + ↓ kinésiophobie + ↑ auto-efficacité."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'effet placebo active le cortex préfrontal et l'insula. Que produit cette activation ?",o:["Inhibition directe des nocicepteurs périphériques","Blocage de la transmission spinothalamique","Activation des réseaux endogènes d'analgésie opioïde et dopaminergique"],a:2,e:"Placebo → CPF + insula activés → ↑ opioïdes endogènes + dopamine + endocannabinoïdes → analgésie mesurable. Ce ne sont pas des effets 'imaginaires'."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les canaux ASIC (sensibles aux acides) s'ouvrent en présence de :",o:["Protons (H⁺) — acidose tissulaire","Stimuli mécaniques intenses","Chaleur > 42°C"],a:0,e:"ASIC = canaux ioniques sensibles aux acides. S'ouvrent quand H⁺ ↑ (acidose) = inflammation, ischémie. Contribuent à la douleur inflammatoire."},
  {ch:"Classification",label:"Classification",type:"direct",q:"L'hyperesthésie est définie comme :",o:["Sensation anormale désagréable spontanée","Douleur face à un stimulus non nociceptif","Perception d'une sensation accrue (pas forcément douloureuse)"],a:2,e:"Hyperesthésie = ↑ sensibilité à tout stimulus. Hypoesthésie = ↓ sensibilité. Dysesthésie = anormale + désagréable. Paresthésie = anormale + non désagréable. Allodynie = douleur sur stimulus non nociceptif."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Dans le modèle du triple réseau, le réseau de saillance (RS) :",o:["Contrôle la mémoire de travail et la planification","Gère le concept de soi et l'identité","Priorise les informations pertinentes — associé à la souffrance"],a:2,e:"RS = insula antérieure + CCA → priorise stimuli pertinents → souffrance. RND = concept de soi. REC = mémoire de travail + processus cognitifs orientés vers objectifs."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"L'insula dans le traitement de la douleur :",o:["Modulation descendante inhibitrice","Uniquement la localisation spatiale","Pont entre système latéral et médial — traite intensité, localisation et affectif"],a:2,e:"L'insula traite intensité + localisation + aspect émotionnel. Elle est le pont entre discriminatif et affectif."},
{ch:"Classification",label:"Classification",type:"direct",q:"Quelle est la définition IASP 2020 de la douleur ?",o:["Expérience sensorielle et émotionnelle désagréable, toujours subjective, influencée par facteurs bps","Réponse réflexe du système nerveux autonome à une lésion","Signal neurologique objectif proportionnel à la lésion"],a:0,e:"IASP 2020 : douleur = subjective, toujours influencée par facteurs bio-psycho-sociaux. Douleur ≠ nociception."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La LTD (dépression à long terme) au niveau spinal :",o:["↓ l'efficacité synaptique → désensibilisation et ↓ douleur","↑ l'efficacité synaptique → sensibilisation centrale","Déclenche le phénomène de wind-up"],a:0,e:"LTD = ↓ efficacité synaptique → désensibilisation → objectif thérapeutique. Obtenue par stimuli basse fréquence / faible intensité. ≠ LTP qui ↑ excitabilité."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La formation réticulaire dans le tronc cérébral :",o:["Est le centre principal de la transduction périphérique","Génère les potentiels d'action des fibres C","Reçoit des informations des neurones de deuxième ordre pour le traitement de la douleur"],a:2,e:"Formation réticulaire = reçoit informations des neurones de 2ème ordre → traitement de la douleur dans le tronc cérébral."},
{ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La rTMS est contre-indiquée en cas de :",o:["Douleur nociceptive légère","Dépression associée à la douleur","Épilepsie non contrôlée et implants ferromagnétiques"],a:2,e:"rTMS contre-indiquée : épilepsie non contrôlée + implants ferromagnétiques proches. Indiquée dans douleur neuropathique."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Quelle est la prévalence de la douleur chronique en Espagne ?",o:["10%","40%","25,9%"],a:2,e:"Espagne : 25,9% (Baromètre 2022). Mondiale : > 30% (Cohen 2021). 39% des patients espagnols ont attendu > 1 an avant diagnostic. Délai moyen = 2,2 ans."},
{ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La PAG est impliquée dans :",o:["La transduction périphérique","La transmission spinothalamique","La modulation descendante de la douleur"],a:2,e:"PAG = centre de la modulation descendante. Fait partie du système PAG-RVM."},

  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel neurotransmetteur excitateur est le plus abondant du système nerveux central ?",o:["Substance P","Glutamate","GABA"],a:1,e:"Glutamate = neurotransmetteur excitateur le plus abondant du SNC. Active AMPA-R et NMDA-R → hyperexcitabilité corne dorsale."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les dendrites d'un neurone ont pour rôle principal :",o:["Transmettre les potentiels d'action vers les terminaisons","Recevoir les signaux synaptiques provenant d'autres neurones","Produire les neurotransmetteurs"],a:1,e:"Dendrites = réception des signaux synaptiques. L'axone = transmission du PA vers les terminaisons. Le soma = réception + synthèse."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel type de nocicepteur répond simultanément à des stimuli mécaniques, thermiques ET chimiques ?",o:["Nocicepteur mécanique","Nocicepteur silencieux","Nocicepteur polymodal"],a:2,e:"Nocicepteurs polymodaux = polyvalents, répondent à tout type de stimulus. Fréquents dans pulpe dentaire. Transmettent via fibres C → douleur diffuse."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La conduction saltatoire est propre aux :",o:["Fibres non myélinisées (groupe C)","Les deux types de fibres","Fibres myélinisées (groupe A)"],a:2,e:"Conduction saltatoire = PA 'saute' de nœud de Ranvier en nœud de Ranvier → beaucoup plus rapide. Propre aux fibres myélinisées Aδ et Aβ."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le ganglion trigéminal contient les corps cellulaires des neurones sensoriels afférents pour :",o:["Les organes viscéraux","Le reste du corps","La tête et le visage"],a:2,e:"Ganglion trigéminal (GT) = tête + visage. Ganglion de la racine dorsale (GRD) = reste du corps. Ganglion nodulaire = nerf vague (viscères)."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Lors de l'hyperpolarisation post-PA, quel phénomène se produit ?",o:["Entrée de Na⁺ → re-dépolarisation","Entrée de Ca²⁺ → libération de neurotransmetteurs","Sortie continue de K⁺ → potentiel membranaire plus négatif que le repos"],a:2,e:"Après repolarisation, les canaux Kv restent ouverts → sortie K⁺ → hyperpolarisation transitoire (potentiel plus négatif que −70 mV). Ensuite la pompe Na⁺/K⁺ rétablit le repos."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le canal TRPA1 est activé par :",o:["La chaleur > 42°C et la capsaïcine","Les stimuli mécaniques exclusivement","Le froid intense, les irritants et les toxines"],a:2,e:"TRPA1 = froid intense + irritants + toxines + produits chimiques. TRPV1 = chaleur > 42°C + protons + capsaïcine."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les interneurones de la corne dorsale jouent un rôle de :",o:["Transmission directe vers le thalamus","Relais entre neurones afférents et efférents","Modulation supraspinale de la douleur"],a:1,e:"Interneurones = relais entre afférents (fibres C, Aδ) et efférents. Peuvent être excitateurs ou inhibiteurs. Leur perte (désinhibition GABAergique) → allodynie."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel peptide opioïde endogène se lie préférentiellement aux récepteurs MOR ?",o:["La dynorphine","Les enképhalines","Les endorphines (β-endorphine)"],a:2,e:"β-endorphine → MOR (préférentiel). Enképhalines → DOR. Dynorphine → KOR. Tous inhibent la libération de neurotransmetteurs excitateurs."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"L'oxyde nitrique (NO) dans la nociception :",o:["Inhibe directement les nocicepteurs périphériques","Bloque les canaux TRPV1","Se diffuse dans d'autres neurones et stimule l'activation du NMDA-R"],a:2,e:"NO = molécule gazeuse mobile → diffuse entre neurones → active seconds messagers → rôle crucial dans transmission nociceptive post-inflammatoire + stimule NMDA-R."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les nocicepteurs thermiques s'activent à partir de :",o:["Chaleur > 37°C ou froid < 10°C","Chaleur > 42°C ou froid < 5°C","Chaleur > 50°C uniquement"],a:1,e:"Nocicepteurs thermiques : chaleur nociceptive > 42°C et froid nociceptif < 5°C. Entre les deux = températures non nociceptives."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La LTD (dépression à long terme) au niveau spinal :",o:["↓ l'efficacité synaptique → désensibilisation et ↓ douleur","↑ l'efficacité synaptique → sensibilisation centrale","Déclenche le phénomène de wind-up"],a:0,e:"LTD = ↓ efficacité synaptique → désensibilisation → objectif thérapeutique. Obtenue par stimuli basse fréquence / faible intensité. ≠ LTP qui ↑ excitabilité."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les orexines (hypocrétines) ont des effets :",o:["Excitateurs sur les récepteurs NMDA","Pro-nociceptifs → ↑ substance P","Antinociceptifs au niveau spinal et supraspinal"],a:2,e:"Orexines = peptides qui exercent des effets antinociceptifs au niveau spinal et supraspinal via récepteurs orexine 1 et 2."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel est le rôle de l'amygdale centrale (CeA) dans la douleur ?",o:["Aspects émotionnels négatifs de la douleur","Localisation et intensité (discriminatif)","Modulation descendante inhibitrice"],a:0,e:"Amygdale centrale (CeA) = aspects émotionnels négatifs. Amygdale basolatérale (BLA) = mémoire de la peur + informations sensorielles polymodales."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La réversibilité de la neuroplasticité dans la douleur chronique est démontrée par :",o:["L'impossibilité de régénérer les fibres C lésées","La permanence des modifications synaptiques","La récupération du volume de matière grise après traitement efficace"],a:2,e:"Études d'imagerie : récupération volume matière grise (amygdale, thalamus, CCA, insula) après traitement efficace et ↓ douleur chronique."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La voie spinothalamique antérieure (médiale) transmet :",o:["La perception émotionnelle et autonome désagréable de la douleur","La localisation précise et l'intensité","Les informations proprioceptives"],a:0,e:"Voie spinothalamique antérieure/médiale → thalamus médial → aspects émotionnels-autonomes. Voie latérale → noyau VPL → aspects discriminatifs."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les canaux ASIC (sensibles aux acides) s'ouvrent en présence de :",o:["Protons (H⁺) — acidose tissulaire","Stimuli mécaniques intenses","Chaleur > 42°C"],a:0,e:"ASIC = canaux ioniques sensibles aux acides. S'ouvrent quand H⁺ ↑ (acidose) = inflammation, ischémie. Contribuent à la douleur inflammatoire."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le locus coeruleus (LC) dans la douleur neuropathique chronique :",o:["Inhibe son activité — effet antinociceptif","N'a aucun rôle dans la douleur neuropathique","Augmente son activité — projections noradrénergiques ascendantes pro-nociceptives"],a:2,e:"LC = neurones noradrénergiques. Dans douleur neuropathique à long terme : ↑ activité LC + projections ascendantes → rôle pro-nociceptif."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel neurotransmetteur est impliqué dans l'analgésie via les récepteurs nicotiniques et muscariniques ?",o:["Sérotonine","Dopamine","Acétylcholine (ACh)"],a:2,e:"ACh = neurotransmetteur cholinergique central. Sa modulation via nAChR (nicotiniques) et mAChR (muscariniques) est impliquée dans l'analgésie."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Dans la sensibilisation centrale, le déséquilibre excitateur/inhibiteur se traduit par :",o:["↑ GABA/glycine ET ↓ glutamate","↑ opioïdes endogènes ET ↓ substance P","↑ glutamate/SP/CGRP ET ↓ GABA/glycine"],a:2,e:"SC = ↑ transmission excitatrice (glutamate, SP, CGRP) + ↓ transmission inhibitrice (GABA, glycine) → hyperexcitabilité des neurones de projection."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le noyau paraventriculaire (PVT) du thalamus peut :",o:["Jouer un rôle uniquement dans la proprioception","Inhiber la douleur systématiquement","Faciliter la douleur via certaines projections thalamiques"],a:2,e:"Le thalamus n'est pas qu'un relais passif. Le noyau PVT peut faciliter la douleur via certaines projections. Le thalamus reçoit aussi des entrées corticales modulatrices."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Les récepteurs cannabinoïdes CB1 et CB2 activés produisent :",o:["↓ AMPc intracellulaire → ↓ effets excitateurs sur les neurones","Activation de PLC → ↑ Ca²⁺ intracellulaire","↑ AMPc → excitation neuronale"],a:0,e:"CB1 + CB2 → couplés à Gi → ↓ AMPc → ↓ excitabilité neuronale + prévention dégranulation mastocytes + ↓ médiateurs pro-inflammatoires."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La noradrénaline (NE) via les récepteurs α2 présynaptiques produit :",o:["Excitation via ↑ AMPc","Activation des voies PLC/PKC","Inhibition de l'entrée de Ca²⁺ → ↓ libération de NE"],a:2,e:"α2 présynaptiques = autorécepteurs → Gi → ↓ Ca²⁺ → ↓ libération NE. α1 et β postsynaptiques → excitateurs."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le rôle du cotransporteur KCC2 dans la douleur neuropathique :",o:["Sa surexpression → ↑ inhibition GABAergique → analgésie","Son blocage → activation Nav → ↑ potentiel d'action","Sa downrégulation → GABA devient dépolarisant (pro-excitateur) → désinhibition"],a:2,e:"KCC2 maintient gradient Cl⁻. Après lésion nerveuse → ↓ KCC2 → Cl⁻ intracellulaire ↑ → GABA devient EXCITATEUR → désinhibition → allodynie."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le CGRP contribue à la physiopathologie de la migraine via :",o:["Activation des récepteurs NMDA dans le cortex → dépression corticale","Blocage de la recapture de sérotonine → vasoconstriction","Vasodilatation des vaisseaux méningés + inflammation neurogène + activation des nocicepteurs périvasculaires"],a:2,e:"CGRP libéré par fibres C → vasodilatation méningée + inflammation neurogène → activation nocicepteurs méningés → douleur migraineuse."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le mécanisme d'action des gabapentinoïdes (gabapentine, prégabaline) est :",o:["Blocage des récepteurs NMDA → ↓ sensibilisation centrale","Activation des récepteurs GABA-B → inhibition présynaptique","Liaison à la sous-unité α2δ des VOCC → ↓ libération de neurotransmetteurs excitateurs"],a:2,e:"Gabapentinoïdes → α2δ des VOCC → ↓ Ca²⁺ → ↓ libération glutamate + SP. Ils ne se lient PAS aux récepteurs GABA."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Dans le modèle du triple réseau, qu'arrive-t-il au réseau exécutif central (REC) dans la douleur chronique ?",o:["Il compense en augmentant son activité → meilleure gestion de la douleur","Il est non affecté — seul le réseau de saillance est modifié","Il est perturbé par la perte d'anticorrélation RS/RND → ↓ mémoire de travail et flexibilité cognitive"],a:2,e:"Douleur chronique → perte anticorrélation RS/RND → RND hyperactif → interfère avec REC → ↓ mémoire de travail + ↓ flexibilité cognitive + ↓ planification. Explique le 'brain fog' chez les fibromyalgiques."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Pourquoi le magnésium (Mg²⁺) est-il important dans la fonction du NMDA-R ?",o:["Mg²⁺ active le canal NMDA en se liant au site glycine","Mg²⁺ inhibe la synthèse de glutamate → ↓ activation NMDA-R","À potentiel de repos, Mg²⁺ bloque le canal NMDA — il faut une dépolarisation préalable pour le lever"],a:2,e:"NMDA-R = triple serrure : glutamate + glycine + dépolarisation membranaire (pour lever le blocage Mg²⁺). À −70 mV, Mg²⁺ bloque le canal même si glutamate + glycine présents."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La modulation descendante de la douleur fait intervenir principalement :",o:["Uniquement les voies dopaminergiques du système limbique","Uniquement les voies cholinergiques du tronc cérébral","Voies opioïdergiques, sérotoninergiques et noradrénergiques PAG → RVM → corne dorsale"],a:2,e:"Modulation descendante : PAG → RVM → corne dorsale via : opioïdes + 5-HT + NE. Ces voies peuvent inhiber OU faciliter la douleur."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La neuromatrice de Melzack propose que la douleur est :",o:["Un signal passif transmis de la périphérie au cortex","Uniquement le résultat de l'activation des fibres C","Une expérience générée par le cerveau (neurosignature), pas uniquement par les inputs périphériques"],a:2,e:"Melzack (1990) : douleur = 'neurosignature' générée activement par la neuromatrice cérébrale. Explique la douleur fantôme."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La 'soupe inflammatoire' contient notamment :",o:["GABA + glycine + endorphines","Glutamate + substance P + CGRP uniquement","Bradykinine + PGE2 + NGF + ATP + H⁺ + histamine"],a:2,e:"Soupe inflammatoire = bradykinine + PGE2 + NGF + ATP + H⁺ + histamine + 5-HT + SP + CGRP → libérés au site lésionnel → sensibilisation périphérique."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La neuropathie des petites fibres (SFN) ne peut pas être diagnostiquée par EMG car :",o:["Les petites fibres transmettent trop lentement pour être détectées","Les petites fibres ne font pas de synapse dans la corne dorsale","L'EMG mesure la conduction des fibres Aβ uniquement — pas des fibres Aδ et C"],a:2,e:"EMG = mesure vitesse de conduction des fibres Aβ (grandes fibres myélinisées). SFN = dysfonctionnement Aδ + C → EMG normal. Diagnostic SFN = biopsie cutanée."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La bradykinine (BK) est un médiateur inflammatoire qui :",o:["Active directement les récepteurs NMDA centraux","Inhibe la libération de prostaglandines","Se lie aux récepteurs B1/B2 des nocicepteurs → pro-nociceptif"],a:2,e:"Bradykinine → récepteurs B1 et B2 → pro-nociceptif + sensibilisation des nocicepteurs. Fait partie de la 'soupe inflammatoire'."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel est le mécanisme de l'analgésie induite par l'exercice (EAIA) ?",o:["L'exercice bloque directement les canaux Nav périphériques","L'exercice induit une acidose locale → activation ASIC → analgésie paradoxale","Libération d'endorphines, endocannabinoïdes, 5-HT et NE → activation des voies descendantes inhibitrices"],a:2,e:"Exercice → ↑ β-endorphines + endocannabinoïdes + 5-HT + NE → activation PAG-RVM → ↑ modulation descendante inhibitrice."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"La zone tegmentale ventrale (VTA) dans la douleur neuropathique chronique :",o:["Constitue le centre primaire de la nociception","Inhibe systématiquement la douleur","Les neurones dopaminergiques présentent une plasticité"],a:2,e:"VTA = neurones dopaminergiques → plasticité dans douleur neuropathique chronique. Impliqué dans la récompense et la motivation → lien douleur/affect négatif."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Le mécanisme d'action du patch de capsaïcine 8% :",o:["Blocage des canaux Nav périphériques → anesthésie locale prolongée","Activation des récepteurs opioïdes locaux → analgésie","Activation prolongée TRPV1 → désensibilisation + défunctionnalisation des fibres C nociceptives"],a:2,e:"Capsaïcine 8% = activation massive et prolongée TRPV1 → désensibilisation (épuisement SP) + défunctionnalisation des fibres C → ↓ transmission nociceptive pendant 3-6 mois."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Dans quel ordre se produisent les étapes du processus nociceptif ?",o:["Transmission → Transduction → Modulation → Perception","Perception → Transduction → Transmission → Modulation","Transduction → Transmission → Modulation → Perception"],a:2,e:"Étapes : 1) Transduction (stimulus → signal électrique), 2) Transmission (périphérie → moelle → cerveau), 3) Modulation (amplification ou inhibition), 4) Perception (expérience consciente)."},
  {ch:"Neurophysiologie",label:"Neurophysiologie",type:"direct",q:"Quel est le lien entre l'activation du TLR4 de la microglie et la douleur neuropathique ?",o:["TLR4 activé → libération d'endorphines → analgésie microgliale","TLR4 activé → induction de la LTD → désensibilisation","TLR4 activé (par débris nerveux) → libération IL-1β + TNF-α + glutamate → ↑ excitabilité spinale"],a:2,e:"Après lésion nerveuse, les débris nerveux activent TLR4 des microglies → cascade inflammatoire (IL-1β, TNF-α, IL-6, chimiokines, glutamate, ATP) → ↑ excitabilité spinale → douleur neuropathique."},
  // ===== APPROCHE CLINIQUE =====
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'ibuprofène inhibe principalement :",o:["Les récepteurs opioïdes MOR","Les cyclooxygénases COX-1 et COX-2 → ↓ prostaglandines","Les canaux Nav périphériques"],a:1,e:"AINS classiques = inhibiteurs non sélectifs COX-1 + COX-2 → ↓ PGE2 → ↓ sensibilisation nocicepteurs. Mécanisme découvert par Vane (1971, Prix Nobel)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La contre-indication principale des AINS classiques en fin de grossesse est :",o:["Ils sont autorisés tout au long de la grossesse","1er trimestre uniquement","3ème trimestre (risque de fermeture prématurée du canal artériel)"],a:2,e:"AINS contre-indiqués au 3ème trimestre : risque fermeture prématurée canal artériel + réduction du liquide amniotique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Les inhibiteurs sélectifs COX-2 (célécoxib) ont moins de gastropathie car :",o:["Ils épargnent la COX-1 qui protège la muqueuse gastrique","Ils activent les récepteurs opioïdes gastriques","Ils inhibent la production d'acide gastrique"],a:0,e:"COX-1 = constitutive → protège muqueuse gastrique. COX-2 = inductible → inflammation. COX-2 sélectifs → moins de gastropathie MAIS ↑ risque thrombotique car ↓ prostacycline."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La naproxène est dosé à :",o:["400-600 mg/8h (max 2400 mg/jour)","50 mg/8-12h (max 150 mg/jour)","250-500 mg/12h (max 1000 mg/jour)"],a:2,e:"Naproxène : 250-500 mg/12h, max 1000 mg/j. Ibuprofène : 400-600 mg/8h, max 2400 mg/j. Diclofénac : 50 mg/8-12h, max 150 mg/j."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Un patient sous anticoagulants doit faire de la kiné avec thérapie manuelle profonde. Quelle précaution ?",o:["Doubler la dose d'anticoagulant avant la séance","Éviter les techniques manuelles trop profondes — risque d'hématome","Appliquer de la chaleur intense pour fluidifier le sang"],a:1,e:"Anticoagulants + thérapie manuelle profonde = risque hématome. Préférer pressions modérées. Pour ponction sèche : contre-indiquée ou protocole strict."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La prégabaline est contre-indiquée ou nécessite un ajustement en cas de :",o:["Épilepsie non contrôlée","Insuffisance hépatique sévère","Insuffisance rénale (clairance < 30 ml/min)"],a:2,e:"Gabapentinoïdes = élimination rénale → ajuster si IRC. Insuffisance hépatique sévère → tapentadol. Épilepsie → tramadol contre-indiqué."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel médicament est particulièrement utile pour la douleur neuropathique avec insomnie associée ?",o:["Ibuprofène (anti-inflammatoire sans effet sur le sommeil)","Duloxétine (prise matinale recommandée)","Amitriptyline (effet sédatif nocturne utile)"],a:2,e:"Amitriptyline = tricyclique → sédatif → utile si insomnie associée. Prise au coucher (10 mg → 25-50 mg). Duloxétine = prise matinale (risque nausées)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Le tapentadol est indiqué dans :",o:["La douleur nociceptive aiguë légère","La douleur neuropathique mixte","La douleur chronique primaire sans composante neuropathique"],a:1,e:"Tapentadol = double mécanisme : agoniste opioïde + inhibiteur recapture NE. Indiqué : douleur modérée à sévère + composante neuropathique mixte."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La crème EMLA® est appliquée :",o:["En massage profond sur la zone douloureuse","12h ON / 12h OFF comme un patch","1g/10cm² sous occlusion 60 minutes avant ponction"],a:2,e:"EMLA (lidocaïne + prilocaïne) = analgésie cutanée pré-ponction. 1g/10cm² sous occlusion 60 min. Patch lidocaïne 5% = 12h ON/12h OFF."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La bupivacaïne infiltrée est plus cardiotoxique que la lidocaïne car :",o:["Elle inhibe la COX-2 cardiaque","Elle active les récepteurs opioïdes cardiaques","Elle se lie plus fortement et plus durablement aux canaux Nav cardiaques"],a:2,e:"Bupivacaïne = anesthésique local puissant et longue durée. Cardiotoxicité ↑ car liaison forte/durable aux Nav cardiaques. Max 2 mg/kg. Lidocaïne max 4,5 mg/kg."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel signal d'alerte impose l'arrêt immédiat d'une séance de kiné sous statines ?",o:["Fatigue musculaire normale post-exercice","Légère myalgie apparaissant après 30 minutes d'effort","Douleur soudaine et intense dans un tendon ou muscle (CK à surveiller)"],a:2,e:"Statines → myalgie/myopathie. Signal d'alerte : douleur musculaire soudaine intense → arrêter + décharger + échographie + orienter médecin (CK > 5x normale → arrêter la statine)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'oxycodone est préféré à la morphine dans certains cas car :",o:["Moins de risque de constipation","N'est pas contre-indiqué en cas d'iléus paralytique","Meilleure biodisponibilité orale"],a:2,e:"Oxycodone = meilleure biodisponibilité orale que morphine. Mêmes indications et contre-indications que morphine."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La stimulation rTMS à 10 Hz sur le cortex préfrontal dorsolatéral est utilisée quand :",o:["La douleur est uniquement nociceptive","Le patient présente une épilepsie bien contrôlée","Il y a une dépression associée à la douleur chronique"],a:2,e:"rTMS 10 Hz sur CPFdl = protocole pour dépression associée à douleur chronique. rTMS HF (≥5-10 Hz) sur M1 controlatéral = douleur neuropathique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'objectif principal d'un bloc anesthésique avant rééducation :",o:["Guérir définitivement la pathologie sous-jacente","Remplacer le traitement de kinésithérapie","Créer une fenêtre d'analgésie pour améliorer la fonction et l'adhésion à l'exercice"],a:2,e:"Bloc anesthésique = fenêtre d'analgésie pour rééducation précoce. Effet modeste et court terme (quelques semaines). Rôle = faciliter l'exercice, pas se substituer à lui."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quelle interaction médicamenteuse peut provoquer un allongement du QT ?",o:["Tramadol + AINS","Morphine + paracétamol","Méthadone + ISRS"],a:2,e:"Méthadone + ISRS → allongement QT → risque torsade de pointes. Tramadol + ISRS → syndrome sérotoninergique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La diathermie profonde est contre-indiquée en cas d'hypotension marquée sous :",o:["Paracétamol","Benzodiazépines","Gabapentine"],a:1,e:"Benzodiazépines + diathermie profonde = contre-indication relative si hypotension marquée. BZD → dépression respiratoire + hypotension → risque aggravé par diathermie."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Les anesthésiques locaux de type amide incluent :",o:["Procaïne et tétracaïne","Lidocaïne et bupivacaïne","Cocaïne et benzocaïne"],a:1,e:"Amides : lidocaïne, bupivacaïne, ropivacaïne, mépivacaïne. Esters : procaïne, tétracaïne, cocaïne. Contre-indication amides : allergie + insuffisance hépatique sévère."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Le principe de la 'quatrième marche' de l'échelle OMS concerne :",o:["L'utilisation combinée de 4 analgésiques simultanément","Le passage obligatoire par les 3 premiers paliers avant toute intervention","Les techniques interventionnelles (blocages, radiofréquence, neuromodulation) pour douleur réfractaire"],a:2,e:"4ème palier = extension pratique (non officielle OMS) : techniques interventionnelles pour douleur réfractaire. Intégré dans 'l'ascenseur analgésique' comme bouton 'insoutenable/réfractaire'."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La prégabaline a des effets indésirables principaux de :",o:["Nausées et hypertension artérielle","Vertiges et vision trouble","Xérostomie et constipation"],a:1,e:"Prégabaline : vertiges + vision trouble + somnolence. Gabapentine : somnolence + œdème + prise de poids. Duloxétine : nausées + transpiration + HTA."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La codéine est un opioïde faible qui agit :",o:["Directement sur les récepteurs MOR sans métabolisation","En inhibant la recapture de sérotonine","En étant convertie en morphine par le CYP2D6 hépatique"],a:2,e:"Codéine = prodrogue → métabolisée en morphine par CYP2D6. Les 'métaboliseurs lents' (génétique) ont peu d'effet analgésique."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel médicament nécessite une prophylaxie systématique par laxatif lors de sa prescription ?",o:["Les AINS (ibuprofène, diclofénac)","Les opioïdes (morphine, oxycodone, fentanyl)","Les gabapentinoïdes (prégabaline)"],a:1,e:"Opioïdes → constipation quasi-systématique (MOR entériques) → toujours prescrire laxatifs prophylactiques."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La péri-durale caudale est une voie d'injection :",o:["Par voie interlaminaire cervicale","Par ponction directe du disque intervertébral","Par le hiatus sacral — approche inférieure de l'espace épidural"],a:2,e:"Péri-durale caudale = hiatus sacral → espace épidural. Voies : interlaminaire, transforaminale, caudale. Indiquée : sciatique aiguë/sévère par hernie discale."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel est l'avantage du tapentadol sur la morphine dans la douleur neuropathique ?",o:["Moins de constipation car ne bloque pas les récepteurs entériques","Pas de risque de dépression respiratoire","Double mécanisme : agoniste MOR + inhibiteur recapture NE → analgésie + ↑ modulation descendante noradrénergique"],a:2,e:"Tapentadol = MOR agoniste + inhibiteur recapture NE → ↑ NE dans voies descendantes → ↑ modulation inhibitrice."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Pourquoi les corticoïdes infiltrés sont-ils déconseillés dans les tendons récemment lésés ?",o:["Ils bloquent la COX-2 locale → absence d'effet anti-inflammatoire","Ils activent les nocicepteurs locaux → aggravation douloureuse","Ils inhibent la synthèse de collagène et la réparation tissulaire → ↑ risque rupture tendineuse"],a:2,e:"Corticoïdes = anti-inflammatoires MAIS inhibent synthèse collagène → fragilisation → ↑ risque rupture si tendon déjà lésé."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La radiofréquence refroidie présente quel avantage par rapport à la conventionnelle ?",o:["Moins de douleur post-opératoire dans tous les cas","Volume de lésion plus important → ↑ probabilité de dénerver la branche médiale","Efficacité de plus longue durée (> 24 mois vs 6-12 mois)"],a:1,e:"RF refroidie = électrode refroidie → ↑ puissance → ↑ volume de lésion thermique → ↑ probabilité de toucher la branche médiale (anatomie variable)."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La tDCS cible principalement quelles zones dans la douleur chronique ?",o:["Thalamus et noyaux parabrachiens","Ganglion de la racine dorsale et corne dorsale","M1 (cortex moteur primaire) et cortex préfrontal dorsolatéral"],a:2,e:"tDCS cible M1 + CPFdl → ↑ modulation descendante + réorganisation réseaux liés à la douleur."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Dans quelle situation la rTMS est-elle particulièrement recommandée en complément de la kiné ?",o:["Lombosciatalgie aiguë par hernie discale L4-L5","Douleur nociceptive aiguë post-traumatique","Douleur neuropathique centrale réfractaire et syndromes douloureux chroniques résistants aux traitements conventionnels"],a:2,e:"rTMS = douleur neuropathique centrale + syndromes chroniques réfractaires. Protocole : 10-20 séances + entretien possible."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"L'éducation à la neuroscience de la douleur (ENP) réduit la douleur en :",o:["Expliquant l'anatomie des lésions tissulaires pour justifier la douleur","Fournissant des exercices spécifiques pour renforcer les structures lésées","Modifiant les croyances sur la douleur → ↓ catastrophisme → ↓ menace perçue → ↓ sensibilisation centrale"],a:2,e:"ENP/PNE (Louw et al.) : expliquer la neurophysiologie → ↓ menace perçue → ↓ catastrophisme → ↑ auto-efficacité + ↑ participation à l'exercice."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quelle interaction médicamenteuse contre-indique l'association duloxétine + tramadol ?",o:["Néphrotoxicité additive par blocage des récepteurs rénaux","Dépression respiratoire synergique","Syndrome sérotoninergique : les deux inhibent la recapture de sérotonine → accumulation massive de 5-HT"],a:2,e:"Duloxétine (IRSNA) + tramadol (inhibiteur recapture 5-HT + opioïde faible) → ↑↑ sérotonine → syndrome sérotoninergique. Urgence médicale. Contre-indication formelle."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Pourquoi l'exercice est-il recommandé en premier dans la douleur chronique primaire non oncologique ?",o:["L'exercice est uniquement recommandé pour des raisons économiques","Les analgésiques sont contre-indiqués dans la douleur chronique primaire","L'exercice cible les mécanismes physiopathologiques (sensibilisation centrale, EAIA, cartes corticales) avec moins d'effets secondaires"],a:2,e:"OMS 2018 + NICE : douleur chronique primaire → exercice + éducation + psychothérapie EN PREMIER. Les analgésiques conventionnels ne sont pas recommandés en 1ère intention."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"La limit principale de l'échelle OMS pour la douleur neuropathique est :",o:["Elle ne comprend pas de palier pour les opioïdes forts","Elle a été créée spécifiquement pour la douleur neuropathique","Elle ne tient pas compte du type de mécanisme — les opioïdes sont moins efficaces sur la composante neuropathique"],a:2,e:"OMS = créée pour douleur oncologique (souvent nociceptive). Douleur neuropathique répond moins bien aux opioïdes → nécessite adjuvants spécifiques."},
  {ch:"Approche clinique",label:"Approche clinique",type:"direct",q:"Quel principe guide le choix de l'adjuvant dans la douleur neuropathique ?",o:["Toujours commencer par la prégabaline indépendamment des comorbidités","Toujours associer un opioïde fort aux adjuvants","Choisir selon la comorbidité : duloxétine si dépression, amitriptyline si insomnie, gabapentine/prégabaline si anxiété"],a:2,e:"Choix adjuvant selon comorbidité : dépression → duloxétine. Insomnie → amitriptyline. Anxiété + douleur → prégabaline/gabapentine."},
  // ===== FACTEURS MODULATEURS =====
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La TCC est particulièrement indiquée en cas de :",o:["Stress élevé avec insomnie et rumination","Catastrophisme élevé, peur du mouvement et faible auto-efficacité","Évitement rigide et paralysie par analyse"],a:1,e:"TCC = catastrophisme + kinésiophobie + ↓ auto-efficacité. ACT = évitement rigide + paralysie. Mindfulness = stress + insomnie + rumination."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Dans l'ACT, le 'moi observateur' correspond à :",o:["La suppression des pensées douloureuses","L'auto-critique systématique des pensées négatives","La capacité à observer ses propres pensées et émotions sans s'y identifier"],a:2,e:"Moi observateur (ACT) = perspective de l'observateur → observer pensées + émotions sans s'y identifier. Permet la défusion cognitive."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'effet placebo analgésique peut être :",o:["Uniquement produit par une substance pharmacologique inactive","Inexistant si le patient sait qu'il reçoit un placebo","Conditionné (appris) même sans substance active si le contexte est favorable"],a:2,e:"Placebo conditionné = cerveau apprend à associer contexte → analgésie. Même en sachant qu'on reçoit un placebo (open-label), des effets analgésiques peuvent persister."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La mindfulness améliore la douleur en réduisant :",o:["Directement l'intensité du signal nociceptif périphérique","La libération de substance P au niveau de la corne dorsale","La réactivité émotionnelle à la douleur (moins de souffrance secondaire)"],a:2,e:"Mindfulness → ↓ réactivité émotionnelle (souffrance secondaire) + ↓ rumination + ↑ régulation autonome. Ne supprime pas la douleur mais change la RELATION avec elle."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La quelle est la différence entre TCC et ACT dans la gestion de la douleur ?",o:["TCC = passive. ACT = active","TCC = long terme. ACT = court terme uniquement","TCC = modifier les pensées. ACT = changer la relation avec les pensées sans les modifier"],a:2,e:"TCC = restructuration cognitive (modifier pensées inadaptées). ACT = défusion cognitive (changer la relation avec les pensées)."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quelle est la distinction entre 'acceptation' (ACT) et 'résignation' ?",o:["Acceptation = ignorer la douleur. Résignation = ressentir la douleur","Elles sont identiques dans le contexte de la douleur chronique","Acceptation = reconnaître la douleur sans lutter ET continuer à vivre selon ses valeurs. Résignation = abandon de la vie active"],a:2,e:"ACT ≠ résignation. Acceptation = présence consciente SANS lutte + engagement actif. Résignation = abandon, passivité."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Comment la mindfulness modifie-t-elle la réponse cérébrale à la douleur ?",o:["↑ activité S1 → meilleure localisation de la douleur","Blocage de la transmission spinothalamique","↓ réactivité amygdalienne + ↑ connectivité CCA-insula + ↑ variabilité de la fréquence cardiaque"],a:2,e:"Mindfulness → réorientation attentionnelle → ↓ réactivité amygdalienne + ↑ connectivité CCA-insula + ↑ variabilité FC (tonus parasympathique)."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'alliance thérapeutique est un facteur prédictif indépendant des résultats cliniques car :",o:["Elle remplace entièrement l'effet de la technique","Elle n'a d'effet que sur la satisfaction du patient, pas sur la douleur","Son influence peut être aussi importante que la technique appliquée"],a:2,e:"Alliance thérapeutique = prédicteur indépendant des résultats musculo-squelettiques. Influence parfois aussi importante que la technique (McParlin et al. 2022)."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quelle est la différence neurobiologique entre l'effet placebo et l'effet nocebo ?",o:["Placebo : GABA central. Nocebo : glutamate central","Placebo : périphérique uniquement. Nocebo : central uniquement","Placebo : opioïdes endogènes + dopamine + endocannabinoïdes. Nocebo : CCK + désactivation opioïdes endogènes"],a:2,e:"Placebo → attentes positives → opioïdes endogènes + dopamine + endocannabinoïdes + ↑ CPF. Nocebo → CCK + ↑ amygdale/zones de menace → hyperalgésie."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Dans l'ACT, l'évitement expérientiel est défini comme :",o:["L'évitement physique des mouvements douloureux uniquement","Une stratégie adaptative pour gérer la douleur à court terme","La tentative de supprimer ou d'éviter les pensées, émotions et sensations douloureuses — maintient la souffrance"],a:2,e:"Évitement expérientiel (ACT) = fuir les expériences internes négatives → paradoxalement amplifie la souffrance. ACT = opposé : accepter ces expériences + agir selon ses valeurs malgré elles."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Pourquoi les 'drapeaux roses' sont-ils un concept important dans le pronostic ?",o:["Ils indiquent une douleur exclusivement nociceptive de bon pronostic","Ils signalent la nécessité d'une imagerie médicale urgente","Leur présence prédit un meilleur pronostic, moins d'invalidité et une meilleure observance thérapeutique"],a:2,e:"Drapeaux roses (Gifford) = facteurs psychosociaux PROTECTEURS. Leur présence → ↑ pronostic + ↓ invalidité + ↑ observance. À encourager activement en clinique."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La synchronisation physiologique entre le thérapeute et le patient lors du toucher peut être mesurée par :",o:["L'activité EEG uniquement","La variabilité de la fréquence cardiaque (VFC) — les rythmes cardiaques et respiratoires se synchronisent","La température cutanée du thérapeute"],a:1,e:"McParlin et al. 2022 : toucher thérapeutique → synchronisation bio-comportementale → rythmes physiologiques (FC, respiration) se synchronisent. Mesurable par VFC."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Comment le modèle enactif guide-t-il la pratique clinique du kiné ?",o:["Le kiné doit se concentrer uniquement sur les structures anatomiques lésées","Le modèle enactif recommande l'immobilité pour protéger l'organisme","Le kiné doit 'reconnecter' le patient à son corps et à son environnement — les 'affordances' comme base du traitement"],a:2,e:"Modèle enactif : kiné → 1) écoute du récit + 2) modifier les affordances + 3) reconnecter positivement corps-environnement + 4) autogestion active."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quelle stratégie renforce simultanément l'auto-efficacité ET le locus de contrôle interne ?",o:["La prescription stricte d'exercices sans explication des mécanismes","L'utilisation exclusive de techniques passives pour éviter l'effort","L'exposition progressive avec participation aux décisions thérapeutiques et feedback positif sur les progrès"],a:2,e:"Exposition progressive + décisions partagées + feedback positif → patient vit des succès (↑ auto-efficacité) + comprend que SES actions font la différence (↑ locus interne). Double bénéfice psychosocial."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"La TCC réduit le catastrophisme. Quel mécanisme neurobiologique sous-tend cette amélioration ?",o:["↓ libération de substance P dans la corne dorsale","↓ activité des canaux TRPV1 périphériques","↑ activité CPFdl → ↑ modulation descendante inhibitrice + ↑ inhibition de l'amygdale"],a:2,e:"TCC → réévaluation cognitive → ↑ activité CPFdl → 1) ↑ modulation descendante + 2) ↑ inhibition de l'amygdale → ↓ réactivité émotionnelle → ↓ catastrophisme. Visible en neuroimagerie."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"Quel processus de l'ACT traite spécifiquement la 'fusion cognitive' avec la douleur ('je suis ma douleur') ?",o:["L'acceptation — tolérer que la douleur soit là","L'action engagée — agir malgré la douleur","La défusion cognitive — prendre de la distance avec les pensées sur la douleur"],a:2,e:"Fusion cognitive = 's'identifier à sa douleur'. Défusion = 'j'ai la pensée que je suis invalide' → distance → la pensée est un événement mental, pas un fait sur moi."},
  {ch:"Facteurs modulateurs",label:"Facteurs modulateurs",type:"direct",q:"L'affrontement actif est associé à quels marqueurs biologiques ?",o:["↑ substance P périphérique par l'exercice → contre-stimulation","Aucun effet biologique mesurable — uniquement psychologique","↓ IL-6 + ↓ cortisol + ↑ système opioïde endogène + ↓ catastrophisme (lié au CPF)"],a:2,e:"Affrontement actif (exercice + autogestion) → ↓ IL-6 (cytokine pro-inflammatoire) + ↓ cortisol (stress) + ↑ opioïdes endogènes + ↑ activité CPF → ↓ catastrophisme."},
  // ===== FACTEURS PSYCHOSOCIAUX =====
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Quelle est la prévalence de la douleur chronique en Espagne ?",o:["10%","40%","25,9%"],a:2,e:"Espagne : 25,9% (Baromètre 2022). Mondiale : > 30% (Cohen 2021). 39% des patients espagnols ont attendu > 1 an avant diagnostic."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Comment les croyances du conjoint sur la douleur influencent-elles le pronostic du patient ?",o:["Le soutien du conjoint aggrave toujours la douleur","Le conjoint n'a aucune influence sur l'évolution de la douleur","Les niveaux de catastrophisme du conjoint et du patient sont corrélés — le catastrophisme du conjoint est un prédicteur influent"],a:2,e:"Lemieux 2013, Noel 2015 : catastrophisme du conjoint ≈ catastrophisme du patient (corrélation modérée). Inclure le conjoint dans l'éducation est bénéfique."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La TCC augmente le volume de matière grise dans le CPFdl. Quel bénéfice clinique direct en résulte ?",o:["↑ libération de substance P → contre-stimulation analgésique","↑ sensibilité des récepteurs opioïdes → ↑ effet des opioïdes","↑ capacité de modulation descendante inhibitrice + ↑ réévaluation cognitive de la douleur → ↓ catastrophisme"],a:2,e:"↑ matière grise CPFdl (Seminowicz 2011) → 1) ↑ modulation descendante (CPF → PAG → RVM → corne dorsale) + 2) ↑ réévaluation cognitive → ↓ catastrophisme + ↓ hypervigilance + ↓ douleur."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Comment l'hypervigilance à la douleur entretient-elle un cercle vicieux dans la douleur chronique ?",o:["↑ attention → ↓ libération GABA → désinhibition périphérique","↑ attention → ↑ libération substance P → inflammation neurogène","↑ attention → ↑ amplification centrale → ↑ douleur perçue → ↑ attention → cercle auto-renforçant"],a:2,e:"Hypervigilance (Crombez 2005) : attention portée à la douleur → activation réseau de saillance → amplification centrale → ↑ douleur → ↑ menace → ↑ attention. Cercle auto-renforçant."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Quelle est la neurobiologie du catastrophisme qui explique son impact sur la douleur ?",o:["↑ libération NGF périphérique → sensibilisation des nocicepteurs","↓ libération de CGRP → ↓ modulation descendante","↓ CPF → ↓ modulation descendante + ↑ amygdale + ↑ activité zones menace → amplification de l'expérience douloureuse"],a:2,e:"Catastrophisme → ↓ activité CPFdl (↓ modulation descendante) + ↑ amygdale (↑ réactivité émotionnelle) + ↑ activité zones anticipation/vigilance → amplification de l'expérience douloureuse."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Pourquoi l'éducation seule ne suffit-elle pas à modifier les comportements de santé des patients douloureux ?",o:["L'éducation est contre-indiquée dans la douleur chronique car augmente l'anxiété","L'éducation est suffisante si elle est répétée régulièrement","La connaissance seule ne change pas les comportements — il faut modifier les croyances, l'auto-efficacité et les barrières comportementales"],a:2,e:"Modèle biopsychosocial : connaissances → nécessaires mais insuffisantes. Pour changer le comportement → modifier les croyances (Leventhal) + auto-efficacité + barrières comportementales."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Le taux de mortalité associé à l'isolement social est comparable à :",o:["Une légère hypertension artérielle","Boire 1-2 verres d'alcool par jour","La consommation de tabac ou l'obésité"],a:2,e:"Étude 308 849 sujets / 7,5 ans : isolement social → ↑ mortalité similaire à tabagisme + obésité. Montre l'impact biologique profond de la connexion sociale sur la santé."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La souffrance se distingue de la douleur car elle :",o:["Est uniquement d'origine psychologique","Est toujours plus intense que la douleur","Menace l'intégrité et l'identité personnelle de l'individu"],a:2,e:"Souffrance = expérience extrêmement négative menaçant l'intégrité + l'identité personnelle. Douleur = expérience sensorielle + émotionnelle. Signes : honte, culpabilité, épuisement."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Quel est le mécanisme par lequel le SSPT (syndrome de stress post-traumatique) augmente le risque de douleur chronique ?",o:["Le SSPT cause directement des lésions nerveuses périphériques","Le SSPT augmente la libération de substance P en périphérie","Hyperactivation axe HPA + amygdale hypersensible + CPF hypofonctionnel → ↑ réactivité menace + ↓ modulation descendante"],a:2,e:"SSPT → hyperactivation axe HPA (cortisol chronique) + amygdale hypersensible + CPF hypofonctionnel → ↑ sensibilisation centrale + ↓ modulation descendante → ↑ vulnérabilité douleur chronique."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Comment le Trauma Informed Care modifie-t-il concrètement la pratique du kinésithérapeute ?",o:["Traiter directement les traumatismes psychologiques lors des séances de kiné","Éviter tout contact physique avec les patients traumatisés","Créer un environnement sécurisant + demander la permission avant tout contact + expliquer chaque geste + respecter l'autonomie du patient"],a:2,e:"TIC en kiné : 1) créer espace sûr + 2) demander permission + 3) expliquer les gestes + 4) respecter l'autonomie. L'objectif = minimiser les obstacles, PAS traiter le trauma (rôle du psy)."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"La neurobiologie de l'isolement social aggrave la douleur via :",o:["L'isolement réduit l'accès aux médicaments → sous-traitement","L'isolement provoque uniquement une dépression sans effet sur la douleur","Activation du CCAd + insula antérieure (mêmes circuits que douleur physique) → amplification centrale de la douleur"],a:2,e:"Douleur sociale (isolement) → CCAd + insula = circuits communs avec douleur physique → ↑ charge douloureuse. Aussi : ↑ cytokines pro-inflammatoires (IL-6) + ↓ opioïdes endogènes."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Quel est le lien entre catastrophisme et risque de suicide dans la douleur chronique ?",o:["Il n'y a aucun lien démontré entre douleur chronique et suicide","La douleur chronique réduit le risque suicidaire car elle mobilise les ressources du patient","Le catastrophisme est un prédicteur indépendant des idées suicidaires dans la douleur chronique"],a:2,e:"Catastrophisme → prédicteur indépendant d'idées suicidaires (Hirsh 2011). Douleur chronique → ↑ risque suicidaire via catastrophisme + dépression + sentiment d'impuissance."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Pourquoi la douleur sociale (rejet, solitude) et la douleur physique partagent-elles les mêmes circuits cérébraux ?",o:["Erreur évolutive sans avantage adaptatif","La douleur sociale est une métaphore — pas de base neurobiologique commune","Hypothèse évolutive : la connexion sociale était vitale pour la survie → le cerveau a utilisé le même système d'alarme pour les deux menaces"],a:2,e:"Eisenberger 2013 : hypothèse évolutive → la disconnexion sociale = menace pour la survie → cerveau utilise le même système d'alarme que la douleur physique (CCAd + insula). Adaptatif pour maintenir les liens sociaux."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Comment les ACEs (expériences négatives de l'enfance) augmentent-elles la vulnérabilité à la douleur chronique ?",o:["Lésion directe des fibres C lors des traumatismes physiques précoces","↑ expression génétique des canaux Nav → hyperexcitabilité périphérique","Hyperactivation de l'axe HPA + modifications neuroplastiques de l'amygdale et CPF → ↑ réactivité à la menace"],a:2,e:"ACEs → stress chronique précoce → hyperactivation axe HPA (cortisol) + modifications amygdale + CPF → système d'alarme hypersensible → ↑ réactivité menace + ↓ modulation descendante → ↑ vulnérabilité douleur chronique adulte."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Dans le modèle peur-évitement, pourquoi la kinésiophobie contribue-t-elle à la chronicisation ?",o:["Elle augmente directement la sensibilisation périphérique","Elle inhibe la modulation descendante par la PAG","Elle maintient le cycle évitement → déconditionnement → ↑ peur → handicap"],a:2,e:"Kinésiophobie → évitement → déconditionnement + ↑ peur → handicap + dépression = cycle de chronicisation (Vlaeyen)."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Quel est le rôle du modèle de Leventhal dans la pratique clinique ?",o:["Mesurer objectivement la sensibilisation centrale","Calculer la posologie exacte des analgésiques","Identifier et modifier les représentations inadaptées de la maladie qui génèrent des comportements contre-productifs"],a:2,e:"Leventhal clinique : 1) explorer les 5 représentations du patient + 2) identifier celles qui génèrent comportements contre-productifs + 3) fournir des informations pour les recadrer. Base de l'éducation thérapeutique."},
  {ch:"Facteurs psychosociaux",label:"Facteurs psychosociaux",type:"direct",q:"Pourquoi les interventions psychosociales améliorent-elles les résultats structurels cérébraux dans la douleur chronique ?",o:["Elles bloquent la microglie → ↓ inflammation centrale","Elles augmentent la libération de BDNF uniquement dans l'hippocampe","Elles augmentent l'activité CPF → plasticité adaptative → ↑ volume matière grise CPFdl → ↑ modulation descendante"],a:2,e:"Interventions psychosociales (TCC) → ↑ activité CPF → ↑ volume matière grise CPFdl (Seminowicz 2011, Shelby 2012) → ↑ modulation descendante + ↓ catastrophisme."},
  // ===== CLASSIFICATION =====
  {ch:"Classification",label:"Classification",type:"direct",q:"La douleur neuropathique est définie comme :",o:["Douleur diffuse sans explication biomédicale","Douleur résultant d'une activation des nocicepteurs sans lésion nerveuse","Douleur causée par une lésion ou une maladie du système somatosensoriel"],a:2,e:"Douleur neuropathique (IASP) = causée par lésion/maladie du système somatosensoriel. Nociceptive = activation nocicepteurs. Nociplastique = altération nociception sans lésion évidente."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La définition de la douleur par Williams et Craig (2016) comprend :",o:["3 composantes : biologique, psychologique et sociale","2 composantes : sensorielle et émotionnelle","4 composantes : sensorielle, émotionnelle, cognitive et sociale"],a:2,e:"Williams & Craig 2016 : 'douleur pénible associée à une lésion réelle ou potentielle, avec composantes sensorielles, émotionnelles, cognitives et sociales.'"},
  {ch:"Classification",label:"Classification",type:"direct",q:"L'hypoalgésie est définie comme :",o:["Perception anormalement exagérée face à un stimulus nociceptif","Perception douloureuse face à un stimulus non nociceptif","Perception réduite de la douleur face à un stimulus nociceptif"],a:2,e:"Hypoalgésie = ↓ perception douloureuse face à stimulus nociceptif. Allodynie = douleur sur stimulus NON nociceptif. Hyperalgésie = ↑ réponse à stimulus nociceptif."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La douleur mixte correspond à :",o:["Douleur uniquement d'origine centrale","Douleur avec une composante nociceptive prédominante","Superposition complexe des types nociceptif, neuropathique et nociplastique"],a:2,e:"Douleur mixte = superposition complexe des 3 types. Fréquente en pratique clinique (ex : lombosciatalgie chronique avec composante nociplastique)."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Dans le modèle du triple réseau, le réseau de saillance (RS) :",o:["Contrôle la mémoire de travail et la planification","Gère le concept de soi et l'identité","Priorise les informations pertinentes — associé à la souffrance"],a:2,e:"RS = insula antérieure + CCA → priorise stimuli pertinents → souffrance. RND = concept de soi. REC = mémoire de travail + processus cognitifs orientés vers objectifs."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Le modèle biomédical considère la douleur comme :",o:["Une expérience subjective multidimensionnelle","Proportionnelle à la nature et l'étendue de la lésion tissulaire","Une propriété émergente de l'interaction personne-environnement"],a:1,e:"Modèle biomédical (XIXe s.) : douleur proportionnelle à la lésion. 'Douleur réelle/organique' ≠ 'douleur fonctionnelle/psychogène'. Ce dualisme est réfuté par les données scientifiques actuelles."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Les critères FACULTATIFS de la douleur nociplastique (IASP 2021) incluent :",o:["Tests neurodynamiques positifs","Distribution neuroanatomique logique","Comorbidités : sensibilité lumière/bruit/odeurs, troubles sommeil, fatigue, problèmes cognitifs"],a:2,e:"IASP 2021 facultatifs (nociplastique probable) : antécédents hypersensibilité + au moins 1 comorbidité (lumière, bruit, odeurs, sommeil, fatigue, cognition)."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Quel est le cluster diagnostique de la douleur neuropathique (Shraim 2021) ?",o:["Douleur diffuse + CSI ≥ 40 + facteurs psychosociaux","Douleur localisée + mécanique + absence de dysesthésies","Distribution dermatomique + antécédents lésion nerveuse + tests neurodynamiques positifs (Sensibilité 88,7%)"],a:2,e:"Cluster neuropathique (n=464) : distribution dermatomique (OR 12,64) + ATCD lésion nerveuse (OR 12,64) + tests neurodynamiques + (OR 14,64). Sensibilité 88,7%, Spécificité 76,6%."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Dans le modèle enactif, les 'affordances' correspondent à :",o:["Les réseaux cérébraux de la douleur","Les médiateurs inflammatoires périphériques","Les opportunités d'action perçues en fonction des capacités et du contexte"],a:2,e:"'Affordances' (Stilwell 2019) = opportunités d'action que l'environnement offre à une personne selon ses capacités. La douleur chronique → monde perçu comme limité + menaçant → ↓ affordances."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La neuropathie des petites fibres (Small Fiber Neuropathy) se caractérise par :",o:["Anomalies caractéristiques à l'EMG conventionnel","Dysfonctionnement des fibres Aβ uniquement","Dysfonctionnement des fibres Aδ et C avec résultats EMG souvent NORMAUX"],a:2,e:"Small Fiber Neuropathy (SFN) = dysfonctionnement Aδ + C. EMG = normal (explore Aβ uniquement). Diagnostic : biopsie cutanée (densité fibres intra-épidermiques)."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Selon Muhammad Yunnus (2008), les termes 'symptômes sans explication médicale' et 'somatisation' doivent être :",o:["Remplacés par 'douleur fonctionnelle'","Utilisés uniquement par les psychiatres","Abandonnés — le dualisme maladie-pathologie n'a aucun fondement rationnel actuel"],a:2,e:"Yunnus 2008 : 'Le début d'une nouvelle ère' — abandon du dualisme maladie-pathologie. Ces termes nuisent à la communication patient-thérapeute et à la qualité des soins."},
  {ch:"Classification",label:"Classification",type:"direct",q:"L'hyperesthésie est définie comme :",o:["Sensation anormale désagréable spontanée","Douleur face à un stimulus non nociceptif","Perception d'une sensation accrue (pas forcément douloureuse)"],a:2,e:"Hyperesthésie = ↑ sensibilité à tout stimulus. Hypoesthésie = ↓ sensibilité. Dysesthésie = anormale + désagréable. Paresthésie = anormale + non désagréable."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Dans le modèle du triple réseau, l'hyperconnectivité entre S1 et le RND signifie :",o:["Le traitement cognitif de la douleur s'améliore","La localisation de la douleur s'améliore","La douleur s'intègre dans le concept de soi — elle devient partie de l'identité du patient"],a:2,e:"Hyperconnectivité S1/RND → la douleur devient centrale dans l'identité du patient. Explique pourquoi le concept de soi change dans la douleur chronique."},
  {ch:"Classification",label:"Classification",type:"direct",q:"L'algorithme de Pain in Motion (Nijs 2016) permet de :",o:["Calculer la posologie exacte des antalgiques","Mesurer l'intensité douloureuse sur une échelle validée","Identifier le mécanisme prédominant de la douleur musculo-squelettique"],a:2,e:"Algorithme Nijs 2016 : classification clinique pour identifier mécanisme prédominant → neuropathique vs nociplastique vs nociceptive → guide l'approche thérapeutique."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Quelle est la signification de l'OR (odds ratio) de 69,79 pour 'douleur localisée dans la zone de lésion' dans le cluster nociceptif ?",o:["69,79% des patients nociceptifs ont ce signe","Ce signe multiplie par 69,79 la probabilité d'une douleur nociceptive si présent — c'est le critère le plus spécifique","Ce signe est présent 69,79 fois plus chez les nociceptifs que chez les nociplastiques"],a:1,e:"OR = 69,79 = si ce signe est présent, la probabilité d'être nociceptif est multipliée par 69,79. C'est le critère LE PLUS SPÉCIFIQUE du cluster nociceptif (Shraim 2021)."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Pourquoi la définition IASP 2020 précise que 'la douleur et la nociception sont des phénomènes distincts' ?",o:["Car la nociception est toujours plus intense que la douleur perçue","Car la nociception est réservée aux animaux, la douleur aux humains","Car la douleur peut exister sans nociception (douleur fantôme) et vice versa (nociception sans douleur sous anesthésie)"],a:2,e:"IASP 2020 : douleur ≠ nociception. Exemples : 1) Douleur sans nociception = douleur fantôme. 2) Nociception sans douleur = sous anesthésie générale ou footballeur blessé qui continue."},
  {ch:"Classification",label:"Classification",type:"direct",q:"La douleur chronique dans la CIM-11 est classée comme :",o:["Uniquement un symptôme d'une autre pathologie","Une condition psychiatrique","Une maladie à part entière (et non uniquement un symptôme)"],a:2,e:"Treede et al. (Pain 2019, IASP) : la douleur chronique dans CIM-11 peut être classée comme maladie à part entière (douleur chronique primaire) ou comme symptôme d'une autre maladie (douleur chronique secondaire)."},
  {ch:"Classification",label:"Classification",type:"direct",q:"En quoi le modèle enactif dépasse-t-il le modèle biopsychosocial ?",o:["Le modèle enactif rejette les facteurs biologiques","Le modèle enactif est plus simple — uniquement environnemental","Le modèle enactif est holiste — corps+esprit+environnement sont indissociables (pas 3 dimensions séparées)"],a:2,e:"BPS = 3 composantes qui interagissent mais restent conceptuellement séparées. Enactif = elles sont fondamentalement INDISSOCIABLES → la douleur émerge de l'INTERACTION elle-même."},
  {ch:"Classification",label:"Classification",type:"direct",q:"Comment différencier cliniquement une douleur neuropathique d'une douleur nociplastique ?",o:["Neuropathique : CSI ≥ 40. Nociplastique : tests neurodynamiques positifs","Elles sont identiques cliniquement — seule l'IRM les différencie","Neuropathique : distribution neuroanatomique logique + antécédents lésion nerveuse. Nociplastique : diffuse, non anatomique, CSI ≥ 40, sans lésion évidente"],a:2,e:"Différenciation : Neuropathique (cluster Shraim) = dermatomique + ATCD lésion nerveuse + neurodynamique +. Nociplastique = diffuse + disproportionnée + CSI ≥ 40. L'imagerie n'est pas le critère."},
{ch:"Classification",label:"Classification",type:"direct",q:"Quelle est l'implication thérapeutique de l'identification d'une douleur nociplastique prédominante ?",o:["Prescrire des AINS puissants pour traiter l'inflammation centrale","Immobiliser le patient pour ↓ les inputs nociceptifs","Cibler la sensibilisation centrale : exercice progressif + ENP + TCC/ACT + ↓ analgésiques conventionnels"],a:2,e:"Douleur nociplastique = SC prédominante → traitement : 1) exercice progressif (↓ SC) + 2) ENP (↓ catastrophisme) + 3) TCC/ACT + 4) ↓ analgésiques conventionnels (peu efficaces sur SC)."},

];